		DxChart.genKey = function () {
			var x = new Uint8Array([
					84, 79, 66, 69, 83, 79, 70, 84, 49, 50, 51, 52, 53, 54, 55, 56,
				]);
			var y = new Uint8Array([
					49, 50, 51, 52, 53, 54, 55, 56, 49, 50, 51, 52, 53, 54, 55, 56, 49, 50,
					51, 52, 53, 54, 55, 56, 49, 50, 51, 52, 53, 54, 55, 56,
				]);
			
			x = String.fromCharCode.apply(null, x);
			y = String.fromCharCode.apply(null, y);
			
			DxChart.publicAESKey = CryptoJS.enc.Utf8.parse(x);
			DxChart.publicAESIV = CryptoJS.enc.Utf8.parse(y);
		};
		DxChart.encryptAES = function (data) {
			var vmode = CryptoJS.mode.CBC;
			var vpadding = CryptoJS.pad.ZeroPadding;
			var encrypted = CryptoJS.AES.encrypt(data, DxChart.publicAESKey, {
					iv: DxChart.publicAESIV,
					mode: vmode,
					padding: vpadding,
				});
			return encrypted.toString();
		};
		DxChart.decryptAES = function (data) {
			var vmode = CryptoJS.mode.CBC;
			var vpadding = CryptoJS.pad.ZeroPadding; //CryptoJS.pad.Pkcs7;
			var decrypted = CryptoJS.AES.decrypt(data, DxChart.publicAESKey, {
					iv: DxChart.publicAESIV,
					mode: vmode,
					padding: vpadding,
				});
			return decrypted.toString(CryptoJS.enc.Utf8);
		};
		
