		DxChart.abs = function () {
			var args = DxChart.getArgs(arguments, "value");
			
			if (typeof args.value === "string") {
				args.value = parseFloat(args.value) || 0;
			}
			
			if (typeof args.value === "number") {
				return Math.abs(args.value);
			}
			
			if (typeof args.value === "object") {
				for (var i in args.value) {
					if (
						typeof args.value[i] === "string" ||
						typeof args.value[i] === "number" ||
						typeof args.value[i] === "object"
					) {
						args.value[i] = DxChart.abs(args.value[i]);
					}
				}
				
				return args.value;
			}
			
			return 0;
		};
		
		DxChart.clear = DxChart.Clear = function (args) {
			var args = DxChart.getArgs(arguments, "canvas,color");
			var obj = args.canvas.__object__;
			var context;
			
			if (!args.canvas) {
				return;
			}
			context = args.canvas.getContext("2d");
			var color = args.color || (obj && obj.get("clearto"));
			DxChart._fireEvent(obj, "onbeforeclear");
			
			//
			// Set the CSS display: to none for DOM text
			//
			if (
				DxChart.text.domNodeCache &&
				typeof DxChart.text.domNodeCache == "object"
			) {
				// 	  var nodeCache = DxChart.text.domNodeCache[args.canvas.id] ||
				// 					  DxChart.text.domNodeCache[args.canvas.__object__.id] || 
				// 					  DxChart.text.domNodeCache[args.canvas._nodeCacheId]
				var id1 = args.canvas.id;
				var id2 = args.canvas.__object__ && args.canvas.__object__.id;
				var id3 = args.canvas._nodeCacheId;
				
				var nodeCache = DxChart.text.domNodeCache[id1] ||
				DxChart.text.domNodeCache[id2] ||
				DxChart.text.domNodeCache[id3];
				
				if(nodeCache){
					for (var i in nodeCache) {
						var el = nodeCache[i];
						
						if (el && el.style) {
							el.style.display = "none";
						}
					}
				}
			}
			//
			// Can now clear the canvas back to fully transparent
			//
			if (
				!color ||
				(color && color === "rgba(0,0,0,0)") ||
				color === "transparent"
			) {
				context.clearRect(
					-100,
					-100,
					args.canvas.width + 200,
					args.canvas.height + 200
				);
				// Reset the globalCompositeOperation
				context.globalCompositeOperation = "source-over";
				if (isNexacroRuntime)
				context.setElementGlobalCompositeOperation(
					context.globalCompositeOperation
				);
			} else if (color) {
				obj.path(
					"fs % fr -100 -100 % %",
					color,
					args.canvas.width + 200,
					args.canvas.height + 200
				);
			} else {
				obj.path(
					"fs % fr -100 -100 % %",
					obj.get("clearto"),
					args.canvas.width + 200,
					args.canvas.height + 200
				);
			}
			
			//if (DxChart.clearAnnotations) {
			//DxChart.clearAnnotations(canvas.id);
			//}
			
			//
			// This removes any background image that may be present
			//
			if (DxChart.Registry.get("background.image." + args.canvas.id)) {
				var img = DxChart.Registry.get("background.image." + args.canvas.id);
				img.style.position = "absolute";
				img.style.left = "-10000px";
				img.style.top = "-10000px";
			}
			
			//
			// This hides the tooltip that is showing IF it has the same canvas ID as
			// that which is being cleared
			//
			if (
				DxChart.Registry.get("tooltip") &&
				obj &&
				!obj.get("tooltipsNohideonclear")
			) {
				DxChart.hideTooltip(args.canvas);
			}
			
			//
			// Set the cursor to default
			//
			if (isNexacroRuntime) {
				args.canvas.cursor = "default";
			} else {
				args.canvas.style.cursor = "default";
			}
			
			DxChart._fireEvent(obj, "onclear");
		};
		
		//
		// Draws the title of the graph
		//
		// @param object  args   An object consisting of the arguments to the function
		//                        o object
		//
		// OR
		//
		// @param object  canvas The canvas object
		//
		DxChart.drawTitle = function () {
			var args = DxChart.getArgs(arguments, "object"),
			obj = args.object,
			halign = "center",
			valign = "center",
			x =
			(obj.canvas.width - obj.marginLeft - obj.marginRight) / 2 +
			obj.marginLeft,
			y = null;
			
			if (obj.properties.titleText == null || obj.properties.titleText == "")
			return;
			var textInfo = DxChart.getTextInfo({
					object: args.object,
					prefix: "title",
				});
			obj.context.beginPath();
			obj.context.fillStyle = textInfo.color;
			if (isNexacroRuntime) obj.context.setElementFillStyle(textInfo.color);
			//
			// If not set then set the size of the text 4 pt higher than
			// the textSize setting. Also set the title to be bold if the
			//bold property isn't set
			//
			if (!DxChart.isNumber(obj.properties.titleFontStyleObj.size)) {
				textInfo.size += 4;
			}
			if (!DxChart.isBoolean(obj.properties.titleFontStyleObj.bold)) {
				textInfo.bold = true;
			}
			
			// Determine the Y coordinate
			y = obj.properties.marginTop - textInfo.size - 5;
			
			if (obj.properties.xaxisPosition === "top") {
				y = obj.canvas.height - obj.properties.marginBottom + textInfo.size + 5;
			}
			
			//
			// Vertically center the text if the key is not present
			// or if it's not positioned in the margin
			//
			if (
				obj.properties.keyData &&
				obj.properties.keyData.length &&
				obj.properties.keyPosition &&
				obj.properties.keyPosition !== "margin"
			) {
				var valign = "center";
			} else if (
				obj.properties.keyData &&
				obj.properties.keyData.length &&
				obj.properties.keyPosition &&
				obj.properties.keyPosition === "margin"
			) {
				var valign = "bottom";
				// Measure the size of the key text
				var keyTextDim = DxChart.measureText(
					"Mg",
					obj.properties.keyLabelsFontStyleObj.bold,
					obj.properties.keyLabelsFontStyleObj.font,
					obj.properties.keyLabelsFontStyleObj.size
				);
				y -= keyTextDim[1];
				
				if (isNexacroRuntime) {
					x = x + keyTextDim[1] * 2;
				}
			} else {
				var valign = "center";
			}
			
			//
			// Now, the titleX and titleY settings override (if set) the above
			if (DxChart.isNumber(obj.properties.titleX)) x = obj.properties.titleX;
			if (DxChart.isNumber(obj.properties.titleY)) y = obj.properties.titleY;
			
			// the titleX and titleY properties can be strings - in
			// which case the added to the calculated coordinate
			if (DxChart.isString(obj.properties.titleX))
			x += parseFloat(obj.properties.titleX);
			if (DxChart.isString(obj.properties.titleY))
			y += parseFloat(obj.properties.titleY);
			
			// Similar to the above - the titleOffsetX and titleOffsetY
			// are more explicit properties for moving the title
			if (DxChart.isNumber(obj.properties.titleOffsetX))
			x += obj.properties.titleOffsetX;
			if (DxChart.isNumber(obj.properties.titleOffsetY))
			y += obj.properties.titleOffsetY;
			
			// Set the default vertical alignment for the title
			if (
				DxChart.isString(obj.properties.titleSubtitle) &&
				obj.properties.titleSubtitle.length > 0
			) {
				valign = "bottom";
			} else {
				valign = "center";
			}
			
			//
			// Allow the user to override the horizontal alignment
			//
			if (DxChart.isString(obj.properties.titleHalign)) {
				halign = obj.properties.titleHalign;
			}
			
			//
			// Allow the user to override the vertical alignment
			//
			if (DxChart.isString(obj.properties.titleValign)) {
				valign = obj.properties.titleValign;
			}
			
			// Set the color
			var oldColor = obj.context.fillStyle;
			obj.context.fillStyle = textInfo.color ? textInfo.color : "black";
			if (isNexacroRuntime)
			obj.context.setElementFillStyle(obj.context.fillStyle);
			// Draw the title
			var ret = DxChart.text({
					object: obj,
					font: textInfo.font,
					size: textInfo.size,
					color: textInfo.color,
					bold: textInfo.bold,
					italic: textInfo.italic,
					x: x,
					y: y,
					text: obj.properties.titleText,
					valign: valign,
					halign: halign,
					tag: "title",
					marker: false,
				});
			
			// Draw the subtitle
			if (
				typeof obj.properties.titleSubtitle === "string" &&
				obj.properties.titleSubtitle.length
			) {
				// Get the size of the title
				// Necessary any more ? var titleSize = textInfo.size;
				
				// Set the default subtitle size if it's null
				if (DxChart.isNull(obj.properties.titleSubtitleFontStyleObj.size)) {
					obj.properties.titleSubtitleFontStyleObj.size = textInfo.size - 4;
				}
				
				var textInfo = DxChart.getTextInfo({
						object: obj,
						prefix: "titleSubtitle",
					});
				
				// Draw the subtitle
				var ret = DxChart.text({
						object: obj,
						font: textInfo.font,
						size: textInfo.size,
						color: textInfo.color,
						bold: textInfo.bold,
						italic: textInfo.italic,
						x: x + obj.properties.titleSubtitleOffsetX,
						y: y + obj.properties.titleSubtitleOffsetY,
						text: obj.properties.titleSubtitle,
						valign: "top",
						halign: halign,
						tag: "subtitle",
						marker: false,
					});
			}
			
			// Reset the fill colour
			obj.context.fillStyle = oldColor;
			if (isNexacroRuntime)
			obj.context.setElementFillStyle(obj.context.fillStyle);
		};
		
		//
		// Gets the mouse X/Y coordinates relative to the canvas
		//
		// @param  args object An object consisting of:
		//                      o event
		// OR
		//
		// @param object e The event object. As such this method should be used in an event listener.
		//
		DxChart.getMouseXY = function (event) {
			if (!event.target) {
				return;
			}
			var el = event.target,
			canvas = el,
			caStyle = canvas.style;
			if (!caStyle) caStyle = {};
			var offsetX = 0,
			offsetY = 0,
			x,
			y,
			borderLeft = caStyle ? parseInt(caStyle.borderLeftWidth) || 0 : 0,
			borderTop = caStyle ? parseInt(caStyle.borderTopWidth) || 0 : 0,
			paddingLeft = caStyle ? parseInt(caStyle.paddingLeft) || 0 : 0,
			paddingTop = caStyle ? parseInt(caStyle.paddingTop) || 0 : 0,
			additionalX = borderLeft + paddingLeft,
			additionalY = borderTop + paddingTop;
			
			if (
				typeof event.offsetX === "number" &&
				typeof event.offsetY === "number"
			) {
				if (isNexacroRuntime) {
					x = event.pageX - borderLeft - paddingLeft;
					y = event.pageY - borderTop - paddingTop;
				} else if (!DxChart.ISIE && !DxChart.ISOPERA) {
					x = event.offsetX - borderLeft - paddingLeft;
					y = event.offsetY - borderTop - paddingTop;
				} else if (DxChart.ISIE) {
					x = event.offsetX - paddingLeft;
					y = event.offsetY - paddingTop;
				} else {
					x = event.offsetX;
					y = event.offsetY;
				}
			} else {
				if (!isNexacroRuntime) {
					if (typeof el.offsetParent !== "undefined") {
						do {
							offsetX += el.offsetLeft;
							offsetY += el.offsetTop;
						} while ((el = el.offsetParent));
					}
				}
				
				x = event.pageX - offsetX - additionalX;
				y = event.pageY - offsetY - additionalY;
				
				if (!isNexacroRuntime) {
					x -= 2 * (parseInt(document.body.style.borderLeftWidth) || 0);
					y -= 2 * (parseInt(document.body.style.borderTopWidth) || 0);
				}
				
				//x += (parseInt(caStyle.borderLeftWidth) || 0);
				//y += (parseInt(caStyle.borderTopWidth) || 0);
			}
			// We return a javascript array with x and y defined
			return [x, y];
		};
		
		//
		// This function returns a two element array of the canvas x/y position in
		// relation to the page
		//
		// @param  args object An object consisting of:
		//                      o canvas
		// OR
		//
		// @param object canvas
		//
		DxChart.getCanvasXY = function (canvas) {
			if (canvas.getBoundingClientRect) {
				var rect = canvas.getBoundingClientRect();
				
				// Add the the current scrollTop and scrollLeft becuase the getBoundingClientRect()
				// method is relative to the viewport - not the document
				var scrollLeft =
				window.pageXOffset || document.documentElement.scrollLeft,
				scrollTop = window.pageYOffset || document.documentElement.scrollTop;
				
				return [rect.x + scrollLeft, rect.y + scrollTop];
			}
			
			var x = 0;
			var y = 0;
			var el = canvas; // !!!
			
			if (isNexacroRuntime) {
				return [x, y];
			} else {
				do {
					x += el.offsetLeft;
					y += el.offsetTop;
					
					// ACCOUNT FOR TABLES IN wEBkIT
					if (
						el.tagName.toLowerCase() == "table" &&
						(DxChart.ISCHROME || DxChart.ISSAFARI)
					) {
						x += parseInt(el.border) || 0;
						y += parseInt(el.border) || 0;
					}
					
					el = el.offsetParent;
				} while (el && el.tagName.toLowerCase() != "body");
				
				var paddingLeft = canvas.style.paddingLeft
				? parseInt(canvas.style.paddingLeft)
				: 0;
				var paddingTop = canvas.style.paddingTop
				? parseInt(canvas.style.paddingTop)
				: 0;
				var borderLeft = canvas.style.borderLeftWidth
				? parseInt(canvas.style.borderLeftWidth)
				: 0;
				var borderTop = canvas.style.borderTopWidth
				? parseInt(canvas.style.borderTopWidth)
				: 0;
				
				if (navigator.userAgent.indexOf("Firefox") > 0) {
					x += parseInt(document.body.style.borderLeftWidth) || 0;
					y += parseInt(document.body.style.borderTopWidth) || 0;
				}
				
				return [x + paddingLeft + borderLeft, y + paddingTop + borderTop];
			}
		};
		
		//
		// This function determines whther a canvas is fixed (CSS positioning) or not. If not it returns
		// false. If it is then the element that is fixed is returned (it may be a parent of the canvas).
		//
		// @param  args object An object consisting of:
		//                      o canvas
		// OR
		//
		// @return Either false or the fixed positioned element
		//
		DxChart.isFixed = function () {
			var args = DxChart.getArgs(arguments, "canvas");
			var i = 0;
			
			while (
				args.canvas &&
				args.canvas.tagName.toLowerCase() != "body" &&
				i < 99
			) {
				if (args.canvas.style.position == "fixed") {
					return args.canvas;
				}
				
				args.canvas = args.canvas.offsetParent;
			}
			
			return false;
		};
		
		//
		// Registers a graph object (used when the canvas is redrawn)
		//
		// @param  args object An object consisting of:
		//                      o object
		// OR
		//
		// @param object obj The object to be registered
		//
		DxChart.register = function () {
			var args = DxChart.getArgs(arguments, "object");
			
			// Allow the registration of functions
			if (typeof args.object === "function") {
				var func = args.object;
				
				// Register a shell object
				var temp = function () {
					this.id = null;
					this.isFunction = true;
					this.canvas = { id: null };
					this.getObjectByXY = function () {
						return false;
					};
					this.get = function () {};
					this.set = function () {};
					this.draw = function () {
						func();
					};
				};
				
				args.object = new temp();
			}
			
			// Checking this property ensures the object is only
			// registered once
			if (
				!args.object.get("noregister") &&
				args.object.get("register") !== false
			) {
				DxChart.REG.add(args.object);
				args.object.set("register", false);
			}
		};
		
		//
		// Causes all registered objects to be redrawn
		//
		// @param  args object An object consisting of:
		//                      o color
		// OR
		//
		// @param string An optional color to use to clear the canvas
		//
		DxChart.redraw = function () {
			var args = DxChart.getArgs(arguments, "color,cvs");
			var objectRegistry = DxChart.REG.objects.byCanvasID;
			
			if (
				typeof args.color === "object" &&
				args.color &&
				typeof args.color.toString === "function" &&
				typeof args.color.toString().indexOf === "function" &&
				args.color.toString().indexOf("HTMLCanvasElement") > -1
			) {
				return DxChart.redrawCanvas(args.cvs, true, args.color);
			}
			
			// Get all of the canvas tags on the page
			if (isNexacroRuntime) {
				for (var i = 0, len = objectRegistry.length; i < len; ++i) {
					if (objectRegistry[i]) {
						DxChart.clear(
							objectRegistry[i][1].canvas,
							args.color ? args.color : null
						);
					}
				}
				
				// 			if (args.cvs && !args.cvs.noclear) {
				// 				DxChart.clear(args.cvs, args.color ? args.color : null);
				// 				/*
				// 				if(DxChart.cache[args.cvs.id]) {
				// 					var ccanvas = DxChart.cache[args.cvs.id].canvas;
				// 					var ccontext = DxChart.cache[args.cvs.id].context;
				// 					DxChart.cache[args.cvs.id].canvas.isclear = true;
				// 					ccanvas.set_width(args.cvs.width);
				// 					ccanvas.set_height(args.cvs.height);
				// 					ccontext.clearRect(0,0,args.cvs.width,args.cvs.height);
				// 				}
				// 				*/
				// 			}
			} else {
				var tags = document.getElementsByTagName("canvas");
				
				for (var i = 0, len = tags.length; i < len; ++i) {
					if (tags[i] && tags[i].__object__ && tags[i].__object__.isDxChart) {
						// Only clear the canvas if it's not Trace'ing - this applies to the Line/Scatter Trace effects
						if (!tags[i].noclear) {
							DxChart.clear(tags[i], args.color ? args.color : null);
							// resize시 line이 흐리멍텅
							tags[i].width = tags[i].width;
							tags[i].__initTranslated__ = false;
							/*
							if(DxChart.cache[tags[i].id]) {
							var ccanvas = DxChart.cache[tags[i].id].canvas;
							var ccontext = DxChart.cache[tags[i].id].context;
							ccanvas.width = tags[i].width;
							ccanvas.height = tags[i].height;
							ccontext.clearRect(0,0,tags[i].width,tags[i].height);
							DxChart.cache[tags[i].id].canvas.isclear = true;
							}
							*/
						}
					}
				}
			}
			
			// 		function doSetTimeout(i, len) {
			// 			if(isNexacroRuntime) {
			// 				var objChart = objectRegistry[i][1];
			// 				nexacro._OnceCallbackTimer.callonce(objChart.canvas.parent,
			// 					function() {
			// 						if(i == 0) DxChart.NOBGCACHE = true;
			// 						var objChart = objectRegistry[i][1];
			// 						DxChart.clear(objChart.canvas);
			// 						objChart.draw();
			// 						if(i == len) DxChart.NOBGCACHE = false;
			// 					}, 50);
			// 			} else {
			// 				setTimeout(function() {
			// 					if(i == 0) DxChart.NOBGCACHE = true;
			// 					var objChart = objectRegistry[i][1];
			// 					/*
			// 					DxChart.clear(objChart.canvas);
			// 					if(DxChart.cache[objChart.canvas.id]) {
			// 						var ccontext = DxChart.cache[objChart.canvas.id].context;
			// 						ccontext.clearRect(0,0,objChart.canvas.width,objChart.canvas.height);
			// 					}
			// 					*/
			// 					DxChart.clear(objChart.canvas);
			// 					objChart.draw();
			// 					if(i == len) DxChart.NOBGCACHE = false;
			// 				}, 50);
			// 			}
			// 		}
			// Go through the object registry and redraw *all* of the canvas'es that have been registered
			for (var i = 0, len = objectRegistry.length; i < len; ++i) {
				if (objectRegistry[i]) {
					var id = objectRegistry[i][0];
					objectRegistry[i][1].draw();
					//doSetTimeout(i,len-1);
				}
			}
		};
		
		DxChart._resizeCanvas = function (canvas) {
			if (!canvas) return;
			
			var objects = DxChart.REG.getObjectsByCanvasID(canvas.id);
			if (!canvas.__object__) return;
			for (var i = 0, len = objects.length; i < len; ++i) {
				if (objects[i]) {
					if (objects[i] && objects[i].isDxChart) {
						if (typeof objects[i].initZoom == "function") objects[i].initZoom();
					}
				}
			}
		};
		
		//
		// Causes all registered objects ON THE GIVEN CANVAS to be redrawn
		//
		// @param  args object An object consisting of:
		//                      o canvas
		//                      o clear
		//                      o color
		//                      o scrollpos
		//                      o clientwidth
		// OR
		//
		// @param canvas object The canvas object to redraw
		// @param clear  bool   Optional boolean which defaults to true and determines whether to clear the canvas
		// @param color  string   삭제후 배경색
		// @param scrollpos  Number   스크롤 시 hscroll pos(gantt의 week에서 사용)
		// @param clientwidth  Number   화면에 표시되는 width(DIV의 width)(gantt의 week에서 사용)
		//
		DxChart.redrawCanvas = function (
			canvas,
			clear,
			color,
			scrollpos,
			clientwidth
		) {
			if (!canvas) return;
			
			var objects = DxChart.REG.getObjectsByCanvasID(canvas.id);
			if (!canvas.__object__) return;
			if (
				DxChart.isNull(clear) ||
				(typeof clear === "boolean" && clear !== false)
			) {
				color = color || canvas.__object__.get("clearto") || "transparent";
				DxChart.clear(canvas, color);
			}
			
			for (var i = 0, len = objects.length; i < len; ++i) {
				if (objects[i]) {
					if (objects[i] && objects[i].isDxChart) {
						// gantt의 처리를 위한 세팅
						
						if (scrollpos) objects[i]._scrollpos = scrollpos;
						if (clientwidth) objects[i]._clientwidth = clientwidth;
						
						objects[i].draw();
					}
				}
			}
		};
		
		//
		// This function draws the background for the bar chart, line chart and scatter chart.
		//
		// @param  args object An object consisting of:
		//                      o object
		// OR
		//
		// @param  object obj The graph object
		//
		DxChart.Background.draw = function () {
			var args = DxChart.getArgs(arguments, "object");
			var properties = args.object.properties,
			height = 0,
			marginLeft = args.object.marginLeft,
			marginRight = args.object.marginRight,
			marginTop = args.object.marginTop,
			marginBottom = args.object.marginBottom,
			marginInner = properties.marginInner,
			variant = properties.variantValue;
			
			if (properties.backgroundUse === false) return;
			
			if (args.object.type == "hbar" || args.object.type == "gantt")
			marginInner = 0;
			
			var graphw = args.object.canvas.width - marginLeft - marginRight;
			var graphh = args.object.canvas.height - marginTop - marginBottom;
			
			if (graphw < 30 || graphh < 10) return;
			
			if (!marginInner) marginInner = 0;
			args.object.context.fillStyle = properties.textColor;
			if (isNexacroRuntime)
			args.object.context.setElementFillStyle(properties.textColor);
			
			// If it's a bar and 3D variant, translate
			if (variant == "3d") {
				args.object.context.save();
				args.object.context.translate(
					properties.variantThreedOffsetX,
					-1 * properties.variantThreedOffsetY
				);
			}
			
			// X axis title (not for the Bar or waterfall charts now - that's done
			// in the newer drawXAxis() function)
			if (
				args.object.type !== "bar" &&
				args.object.type !== "heatmap" &&
				args.object.type !== "waterfall" &&
				args.object.type !== "hbar" &&
				args.object.type !== "line" &&
				args.object.type !== "gantt" &&
				args.object.type !== "scatter" &&
				typeof properties.xaxisTitle === "string" &&
				properties.xaxisTitle.length
			) {
				var size = properties.textFontStyleObj.size + 2;
				//var font   = properties.textFont;
				//var bold   = properties.xaxisTitleBold;
				//var italic = properties.xaxisTitleItalic;
				
				//if (typeof properties.xaxisTitleSize === 'number') {
				//    size = properties.xaxisTitleSize;
				//}
				
				//if (typeof properties.xaxisTitleFont === 'string') {
				//    font = properties.xaxisTitleFont;
				//}
				
				var hpos =
				(args.object.canvas.width - marginLeft - marginRight) / 2 + marginLeft;
				var vpos = args.object.canvas.height - marginBottom + 25;
				
				if (typeof properties.xaxisTitlePos === "number") {
					vpos =
					args.object.canvas.height - marginBottom * properties.xaxisTitlePos;
				}
				
				// Specifically specified X/Y positions
				if (typeof properties.xaxisTitleX === "number") {
					hpos = properties.xaxisTitleX;
				}
				
				if (typeof properties.xaxisTitleY === "number") {
					vpos = properties.xaxisTitleY;
				}
				
				// Get the text configuration
				var textInfo = DxChart.getTextInfo({
						object: args.object,
						prefix: "xaxisTitle",
					});
				
				DxChart.text({
						object: args.object,
						
						font: textInfo.font,
						size: textInfo.size,
						color: textInfo.color,
						bold: textInfo.bold,
						italic: textInfo.italic,
						
						x: hpos,
						y: vpos,
						text: properties.xaxisTitle,
						halign: "center",
						valign: "top",
						tag: "xaxis.title",
					});
			}
			
			// Y axis title
			if (
				args.object.type !== "bar" &&
				args.object.type !== "heatmap" &&
				args.object.type !== "waterfall" &&
				args.object.type !== "hbar" &&
				args.object.type !== "line" &&
				args.object.type !== "gantt" &&
				args.object.type !== "scatter" &&
				typeof properties.yaxisTitle === "string" &&
				properties.yaxisTitle.length
			) {
				var size = properties.textFontStyleObj.size + 2;
				var font = properties.textFontStyleObj.face;
				var italic = properties.textFontStyleObj.italic;
				var angle = 270;
				var bold = properties.yaxisTitleBold;
				var color = properties.yaxisTitleColor;
				
				if (typeof properties.yaxisTitlePos == "number") {
					var yaxis_title_pos = properties.yaxisTitlePos * marginLeft;
				} else if (
					args.object.type === "hbar" &&
					DxChart.isNull(properties.yaxisTitlePos)
				) {
					var sizexx =
					typeof args.object.yaxisLabelsFontStyleObj.size === "number"
					? args.object.yaxisLabelsFontStyleObj.size
					: properties.textFontStyleObj.size;
					var yaxis_title_pos =
					properties.marginLeft - args.object.yaxisLabelsFontStyleObj.size;
				} else {
					if (args.object && args.object.scale2) {
						var yaxisTitleDimensions = DxChart.measureText({
								text: args.object.scale2.labels[
									args.object.scale2.labels.length - 1
								],
								bold:
								typeof properties.yaxisScaleBold === "boolean"
								? properties.yaxisScaleBold
								: properties.textFontStyleObj.bold,
								font: properties.yaxisScaleFont || properties.textFontStyleObj.face,
								size:
								typeof properties.yaxisScaleSize === "number"
								? properties.yaxisScaleSize
								: properties.textFontStyleObj.size,
							});
					} else {
						// This is here to allow for the drawing API background
						// object
						yaxisTitleDimensions = [0, 0];
					}
					
					var yaxis_title_pos =
					properties.marginLeft - yaxisTitleDimensions[0] - 7;
				}
				if (typeof properties.yaxisTitleFontStyleObj.size === "number") {
					size = properties.yaxisTitleFontStyleObj.size;
				}
				
				if (typeof properties.yaxisTitleFontStyleObj.italic === "boolean") {
					italic = properties.yaxisTitleFontStyleObj.italic;
				}
				
				if (typeof properties.yaxisTitleFontStyleObj.face === "string") {
					font = properties.yaxisTitleFontStyleObj.face;
				}
				
				if (
					properties.yaxisTitleAlign == "right" ||
					properties.yaxisTitlePosition == "right" ||
					(args.object.type === "hbar" &&
						properties.yaxisPosition === "right" &&
						typeof properties.yaxisTitleAlign === "undefined" &&
						typeof properties.yaxisTitlePosition === "undefined")
				) {
					angle = 90;
					yaxis_title_pos =
					typeof properties.yaxisTitlePos === "number"
					? args.object.canvas.width -
					marginRight +
					properties.yaxisTitlePos * marginRight
					: args.object.canvas.width -
					marginRight +
					(properties.yaxisLabelsFontStyleObj.size ||
						properties.textFontStyleObj.size) +
					10;
				}
				var y =
				(args.object.canvas.height - marginTop - marginBottom) / 2 + marginTop;
				
				// Specifically specified X/Y positions
				if (typeof properties.yaxisTitleX === "number") {
					yaxis_title_pos = properties.yaxisTitleX;
				}
				
				if (typeof properties.yaxisTitleY === "number") {
					y = properties.yaxisTitleY;
				}
				
				args.object.context.fillStyle = color;
				if (isNexacroRuntime) args.object.context.setElementFillStyle(color);
				
				// Get the text configuration
				var textInfo = DxChart.getTextInfo({
						object: args.object,
						prefix: "yaxisTitle",
					});
				
				DxChart.text({
						object: args.object,
						
						font: textInfo.font,
						size: textInfo.size,
						color: textInfo.color,
						bold: textInfo.bold,
						italic: textInfo.italic,
						
						x: yaxis_title_pos,
						y: y,
						valign: "bottom",
						halign: "center",
						angle: angle,
						text: properties.yaxisTitle,
						tag: "yaxis.title",
						accessible: false,
					});
			}
			//
			// If the background color is spec ified - draw that. It's a rectangle that fills the
			// entire area within the margins
			//
			var bgcolor = properties.backgroundColor;
			if (bgcolor) {
				if (args.object.type == "map") {
					args.object.context.fillStyle = DxChart.parseGradient(
						args.object,
						bgcolor,
						0,
						0,
						args.object.canvas.width,
						args.object.canvas.height
					);
					if (isNexacroRuntime)
					args.object.context.setElementFillStyle(
						args.object.context.fillStyle
					);
					args.object.context.fillRect(
						0,
						0,
						args.object.canvas.width,
						args.object.canvas.height
					);
				} else {
					args.object.context.fillStyle = DxChart.parseGradient(
						args.object,
						bgcolor,
						marginLeft + 0.5,
						marginTop + 0.5,
						args.object.canvas.width - marginLeft - marginRight,
						args.object.canvas.height - marginTop - marginBottom
					);
					if (isNexacroRuntime)
					args.object.context.setElementFillStyle(
						args.object.context.fillStyle
					);
					args.object.context.fillRect(
						marginLeft + 0.5,
						marginTop + 0.5,
						args.object.canvas.width - marginLeft - marginRight,
						args.object.canvas.height - marginTop - marginBottom
					);
				}
			}
			
			//
			// Draw horizontal background bars
			//
			var numbars = properties.yaxisLabelsCount || 5;
			
			// If the backbgroundBarcount property is set use that
			if (typeof properties.backgroundBarsCount === "number") {
				numbars = properties.backgroundBarsCount;
			}
			// Calculate the height of the bars
			var barHeight =
			(args.object.canvas.height - marginBottom - marginTop) / numbars;
			var dumvalue = 0;
			if (isNexacroRuntime) {
				dumvalue = 1;
			}
			if (properties.backgroundBarsColor1) {
				args.object.context.beginPath();
				args.object.context.fillStyle = properties.backgroundBarsColor1;
				if (isNexacroRuntime)
				args.object.context.setElementFillStyle(
					properties.backgroundBarsColor1
				);
				args.object.context.strokeStyle = properties.backgroundBarsColor1;
				if (isNexacroRuntime)
				args.object.context.setElementStrokeStyle(
					args.object.context.strokeStyle
				);
				height = args.object.canvas.height - marginBottom;
				
				for (var i = 0; i < numbars; i += 2) {
					args.object.context.rect(
						marginLeft,
						i * barHeight + marginTop,
						args.object.canvas.width - marginLeft - marginRight,
						barHeight + dumvalue
					);
				}
				args.object.context.fill();
			}
			
			if (properties.backgroundBarsColor2) {
				args.object.context.beginPath();
				args.object.context.fillStyle = properties.backgroundBarsColor2;
				if (isNexacroRuntime)
				args.object.context.setElementFillStyle(
					properties.backgroundBarsColor2
				);
				args.object.context.strokeStyle = properties.backgroundBarsColor2;
				if (isNexacroRuntime)
				args.object.context.setElementStrokeStyle(
					args.object.context.strokeStyle
				);
				
				for (var i = 1; i < numbars; i += 2) {
					args.object.context.rect(
						marginLeft,
						i * barHeight + marginTop,
						args.object.canvas.width - marginLeft - marginRight,
						barHeight + dumvalue
					);
				}
				
				args.object.context.fill();
			}
			
			// 7.27
			if (properties.backgroundEffect && properties.backgroundEffect != "") {
				var width =
				args.object.canvas.width -
				args.object.marginLeft -
				args.object.marginRight;
				var height =
				args.object.canvas.height -
				args.object.marginTop -
				args.object.marginBottom;
				var halfWidth = args.object.marginLeft + width / 2;
				var halfHeight = args.object.marginTop + height / 2;
				
				args.object.adjustSpace = {
					x: args.object.marginLeft,
					y: args.object.marginTop,
					r: args.object.marginLeft + width,
					b: args.object.marginTop + height,
				};
				
				if (properties.backgroundEffect == "WaterColor") {
					this.waterColorCnt = 0;
					if (args.object.waterCoord) {
						for (var i = 0, len = args.object.waterCoord.length; i < len; i++) {
							args.object.waterCoord[i] = null;
						}
					}
					args.object.waterCoord = [];
					if (args.object.waterColorSeq == undefined)
					args.object.waterColorSeq = 0;
					args.object.waterColorSeq++;
					
					args.object.context.globalCompositeOperation = "hard-light"; // 'xor';
					if (isNexacroRuntime)
					args.object.context.setElementGlobalCompositeOperation("hard-light");
					var svAlpha = args.object.context.globalAlpha;
					args.object.context.globalAlpha =
					properties.backgroundEffectAlpha || 0.25;
					if (isNexacroRuntime)
					args.object.context.setElementGlobalAlpha(
						args.object.context.globalAlpha
					);
					for (var i = 0, len = 10; i < len; i++) {
						args.object.waterCoord.push(
							new WaterColor({
									ctx: args.object.context,
									size: width * (0.7 + Math.random() * 0.1),
									x: halfWidth + Math.cos((i / len) * DxChart.TWOPI) * halfWidth,
									y: halfHeight + Math.sin((i / len) * DxChart.TWOPI) * halfHeight,
									minColor: properties.backgroundMinColorCode || 0,
									maxColor: properties.backgroundMaxColorCode || 255,
									parentNode: args.object,
									waterColorSeq: args.object.waterColorSeq,
								})
						);
					}
					
					args.object.context.globalCompositeOperation = "source-over"; // 'xor';
					if (isNexacroRuntime)
					args.object.context.setElementGlobalCompositeOperation("source-over");
					args.object.context.globalAlpha = svAlpha;
				} else if (properties.backgroundEffect == "Lamp") {
					args.object.context.globalCompositeOperation = "lighter"; // 'xor';
					if (isNexacroRuntime)
					args.object.context.setElementGlobalCompositeOperation("lighter");
					
					var lamp = new BgLamp({
							context: args.object.context,
							canvas: args.object.canvas,
							radius: properties.backgroundEffectLampRadius,
							count: properties.backgroundEffectLampCount,
							blur: properties.backgroundEffectLampBlur,
							backgroundColors: properties.backgroundEffectLampBackgroundColors,
							colors: properties.backgroundLampColors,
						});
					args.object.context.globalCompositeOperation = "source-over"; // 'xor';
					if (isNexacroRuntime)
					args.object.context.setElementGlobalCompositeOperation("source-over");
				} else if (properties.backgroundEffect == "Crystal") {
					args.object.context.globalCompositeOperation = "lighter"; // 'xor';
					if (isNexacroRuntime)
					args.object.context.setElementGlobalCompositeOperation("lighter");
					
					var crystal = new BgCrystal({
							context: args.object.context,
							canvas: args.object.canvas,
							color: properties.backgroundEffectCrystalColor,
						});
					args.object.context.globalCompositeOperation = "source-over"; // 'xor';
					if (isNexacroRuntime)
					args.object.context.setElementGlobalCompositeOperation("source-over");
				} else if (properties.backgroundEffect == "Ball") {
					var ticker = 0,
					Balls = [],
					maxBalls = 10,
					easing = 1 / 10;
					
					args.object.context.globalCompositeOperation = "lighten"; // 'xor';
					if (isNexacroRuntime)
					args.object.context.setElementGlobalCompositeOperation("lighten");
					var svAlpha = args.object.context.globalAlpha;
					args.object.context.globalAlpha =
					properties.backgroundEffectAlpha || 0.25;
					if (isNexacroRuntime)
					args.object.context.setElementGlobalAlpha(
						args.object.context.globalAlpha
					);
					if (args.object.Balls) {
						for (var i = 0, len = args.object.Balls.length; i < len; i++) {
							args.object.Balls[i] = null;
						}
					}
					
					args.object.Balls = [];
					var ball;
					for (let i = 0; i < 10; i++) {
						ball = new BgBall({
								ctx: args.object.context,
								startColor: properties.backgroundEffectBallStartColor,
								endColor: properties.backgroundEffectBallEndColor,
								parentNode: args.object,
							});
						Balls.push(ball);
						//ball.update();
						ball.draw();
					}
					args.object.Balls = Balls;
					
					args.object.context.globalCompositeOperation = "source-over"; // 'xor';
					if (isNexacroRuntime)
					args.object.context.setElementGlobalCompositeOperation("source-over");
					args.object.context.globalAlpha = svAlpha;
				} else if (properties.backgroundEffect == "Wave") {
					var svAlpha = args.object.context.globalAlpha;
					args.object.context.globalAlpha =
					properties.backgroundEffectAlpha || 0.25;
					if (isNexacroRuntime)
					args.object.context.setElementGlobalAlpha(
						args.object.context.globalAlpha
					);
					if (args.object.Waves) {
						args.object.Waves = null;
					}
					args.object.Waves = new BgWaves({
							canvas: args.object.canvas,
							ctx: args.object.context,
							waves: properties.backgroundEffectWaveCount || 3,
							hue: properties.backgroundEffectWaveHue || [11, 14],
							width: width,
							parentNode: args.object,
							alpha: properties.backgroundEffectAlpha,
							background: properties.backgroundEffectBackColorUse,
							backColor1: properties.backgroundEffectColor1,
							backColor2: properties.backgroundEffectColor2,
						});
					args.object.Waves.render();
					args.object.context.globalAlpha = svAlpha;
				}
			}
			
			// Close any errantly open path
			args.object.context.beginPath();
			//
			// The background grid is cached
			//
			var func = function (obj, cacheCanvas, cacheContext) {
				// Draw the background grid
				if (properties.backgroundGrid) {
					properties.backgroundGridHlinesCount += 0.0001;
					
					// If autofit is specified, use the .numhlines and .numvlines along with the width to work
					// out the hsize and vsize
					if (properties.backgroundGridAutofit) {
						//
						// Align the grid to the tickmarks
						//
						if (properties.backgroundGridAutofitAlign) {
							// Align the horizontal lines
							if (obj.type === "hbar") {
								obj.set("backgroundGridHlinesCount", obj.data.length);
							}
							
							// Align the vertical lines for the line
							if (obj.type === "line") {
								if (typeof properties.backgroundGridVlinesCount === "number") {
									// Nada
								} else if (
									properties.xaxisLabels &&
									properties.xaxisLabels.length
								) {
									obj.set(
										"backgroundGridVlinesCount",
										properties.xaxisLabels.length - 1
									);
								} else {
									obj.set(
										"backgroundGridVlinesCount",
										obj.data[0].length > 0 ? obj.data[0].length - 1 : 0
									);
								}
							} else if (obj.type === "waterfall") {
								obj.set(
									"backgroundGridVlinesCount",
									obj.data.length + (properties.totalUse ? 1 : 0)
								);
								
								// Align the vertical lines for the bar
							} else if (obj.type === "bar") {
								// 13/12/2018
								//
								// Updated to be the same as the number of data points
								//
								obj.set("backgroundGridVlinesCount", obj.data.length);
								
								// Align the vertical lines for the Scatter
							} else if (obj.type === "scatter") {
								if (typeof properties.backgroundGridVlinesCount !== "number") {
									// Set the number of grid lines to the same
									// as the number of labels
									if (
										DxChart.isArray(properties.xaxisLabels) &&
										properties.xaxisLabels.length
									) {
										obj.set(
											"backgroundGridVlinesCount",
											properties.xaxisLabels.length
										);
										
										// No labels - set the number of grid lines
										// to 10
									} else {
										obj.set("backgroundGridVlinesCount", 10);
									}
								}
								
								// Gantt
							} else if (obj.type === "gantt") {
								if (typeof obj.get("backgroundGridVlinesCount") === "number") {
									// Nothing to do here
								} else {
									obj.set("backgroundGridVlinesCount", properties.xaxisScaleMax);
								}
								
								obj.set("backgroundGridHlinesCount", obj.data.length);
								
								// HBar
							} else if (
								obj.type === "hbar" &&
								DxChart.isNull(properties.backgroundGridHlinesCount)
							) {
								obj.set("backgroundGridHlinesCount", obj.data.length);
							}
						}
						
						var vsize = 0;
						if (obj.type === "line") {
							// hsji
							vsize =
							(cacheCanvas.width - marginLeft - marginRight - marginInner * 2) /
							properties.backgroundGridVlinesCount;
						} else {
							vsize =
							(cacheCanvas.width - marginLeft - marginRight) /
							properties.backgroundGridVlinesCount;
						}
						var hsize =
						(cacheCanvas.height - marginTop - marginBottom) /
						properties.backgroundGridHlinesCount;
						obj.set("backgroundGridVsize", vsize);
						obj.set("backgroundGridHsize", hsize);
					}
					
					if (
						/*properties.backgroundGridVlines && */ properties.backgroundVBarsColor1 &&
						properties.backgroundVBarsColor2
					) {
						var width = cacheCanvas.width - marginRight;
						var nCnt = 0;
						var nX = marginLeft;
						var rootx = marginLeft;
						if (args.object.type === "line") {
							rootx = marginLeft + marginInner;
						}
						for (var x = rootx; Math.round(x) <= width; x += vsize) {
							if (x + vsize / 2 > width) break;
							cacheContext.beginPath();
							nCnt++;
							if (nCnt % 2 == 1) {
								//  홀
								cacheContext.fillStyle = properties.backgroundVBarsColor1;
								if (isNexacroRuntime)
								cacheContext.setElementFillStyle(
									properties.backgroundVBarsColor1
								);
							} else {
								cacheContext.fillStyle = properties.backgroundVBarsColor2;
								if (isNexacroRuntime)
								cacheContext.setElementFillStyle(
									properties.backgroundVBarsColor2
								);
							}
							cacheContext.rect(
								x,
								marginTop,
								vsize,
								obj.canvas.height - marginTop - marginBottom
							);
							cacheContext.closePath();
							cacheContext.fill();
						}
					}
					
					cacheContext.beginPath();
					
					cacheContext.lineWidth = properties.backgroundGridLineWidth
					? properties.backgroundGridLineWidth
					: 1;
					if (isNexacroRuntime)
					cacheContext.setElementLineWidth(cacheContext.lineWidth);
					cacheContext.strokeStyle = properties.backgroundGridColor;
					if (isNexacroRuntime)
					cacheContext.setElementStrokeStyle(cacheContext.strokeStyle);
					
					// Dashed background grid
					//if (properties.backgroundGridDashed && typeof cacheContext.setLineDash == 'function') {
					if (properties.backgroundGridDashed) {
						//cacheContext.setLineDash([3,5]);
						if (isNexacroRuntime) cacheContext.setElementLineStyle("dashed");
						else cacheContext.setLineDash([3, 5]);
					}
					
					// Dotted background grid
					//if (properties.backgroundGridDotted && typeof cacheContext.setLineDash == 'function') {
					if (properties.backgroundGridDotted) {
						//cacheContext.setLineDash([1,3]);
						if (isNexacroRuntime) cacheContext.setElementLineStyle("dotted");
						else cacheContext.setLineDash([1, 3]);
					}
					
					// Draw the horizontal lines
					if (properties.backgroundGridHlines) {
						height = cacheCanvas.height - marginBottom;
						var hsize = properties.backgroundGridHsize;
						for (y = marginTop; y <= height; y += hsize) {
							//                             cacheContext.moveTo(marginLeft, Math.round(y));
							//                             cacheContext.lineTo(args.object.canvas.width - marginRight, Math.round(y));
							cacheContext.moveTo(marginLeft, parseInt(y));
							cacheContext.lineTo(
								args.object.canvas.width - marginRight,
								parseInt(y)
							);
							if (
								args.object.properties.variantValue === "3d" &&
								args.object.type === "bar" &&
								args.object.properties.backgroundGridThreedYaxis
							) {
								//cacheContext.moveTo(marginLeft, Math.round(y));
								cacheContext.moveTo(marginLeft, parseInt(y));
								cacheContext.lineTo(
									marginLeft - args.object.properties.variantThreedOffsetX,
									parseInt(y) + args.object.properties.variantThreedOffsetY
									//Math.round(y) + args.object.properties.variantThreedOffsetY
								);
							}
						}
					}
					
					// Draw the vertical lines
					if (properties.backgroundGridVlines) {
						var width = cacheCanvas.width - marginRight;
						var vsize = properties.backgroundGridVsize;
						var nCnt = 0;
						// hsji
						var arrMoveData = [];
						var arrLineData = [];
						if (args.object.type === "line") {
							for (
								var x = marginLeft + marginInner;
								Math.round(x) <= width;
								x += vsize
							) {
								arrMoveData.push([Math.round(x), marginTop]);
								arrLineData.push([
										Math.round(x),
										obj.canvas.height - marginBottom,
									]);
							}
						} else {
							for (var x = marginLeft; Math.round(x) <= width; x += vsize) {
								arrMoveData.push([Math.round(x), marginTop]);
								arrLineData.push([
										Math.round(x),
										obj.canvas.height - marginBottom,
									]);
							}
						}
						var s = 0;
						var e = arrMoveData.length;
						if (marginInner > 0) {
							s = 1;
							e = e - 1;
						}
						for (var x = s; x < e; x++) {
							cacheContext.moveTo(arrMoveData[x][0], arrMoveData[x][1]);
							cacheContext.lineTo(arrLineData[x][0], arrLineData[x][1]);
						}
						arrMoveData = arrLineData = null;
						
						// 						for (var x=marginLeft+marginInner; Math.round(x)<=width; x+=vsize) {
						// 							cacheContext.moveTo(Math.round(x), marginTop);
						// 							cacheContext.lineTo(Math.round(x), obj.canvas.height - marginBottom);
						// 						}
					}
					if (properties.backgroundGridBorder) {
						// Make sure a rectangle, the same colour as the grid goes around the graph
						cacheContext.strokeStyle = properties.backgroundGridColor;
						if (isNexacroRuntime)
						cacheContext.setElementStrokeStyle(cacheContext.strokeStyle);
						cacheContext.strokeRect(
							Math.round(marginLeft),
							Math.round(marginTop),
							obj.canvas.width - marginLeft - marginRight,
							obj.canvas.height - marginTop - marginBottom
						);
					}
				}
				cacheContext.stroke();
				
				// Ensure the grid is drawn before continuing
				cacheContext.beginPath();
				cacheContext.closePath();
			};
			
			//func(args.object,args.object.canvas,args.object.context);
			// Now a cached draw in newer browsers
			if (properties.backgroundGrid) {
				if (isNexacroRuntime) {
					func(args.object, args.object.canvas, args.object.context);
				} else {
					if (properties.backgroundNoCache === true) {
						func(args.object, args.object.canvas, args.object.context);
					} else {
						DxChart.cachedDraw(
							args.object,
							args.object.uid, //args.object.uid + '_background',
							func
						);
						DxChart.cacheDelete(
							args.object,
							args.object.uid, //args.object.uid + '_background',
							func
						);
					}
				}
			}
			
			// If it's a bar and 3D variant, translate
			if (variant == "3d") {
				args.object.context.restore();
			}
			
			// Reset the line dash
			if (typeof args.object.context.setLineDash == "function") {
				if (isNexacroRuntime) args.object.context.setElementLineStyle("dash");
				//24.01.25 sj.jo 속도 저하로 인해 값 변경
				//else args.object.context.setLineDash([1,0]);
				else args.object.context.setLineDash([]);
			}
			
			args.object.context.stroke();
			
			// Draw the title if one is set
			if (typeof args.object.properties.titleText == "string") {
				DxChart.drawTitle(args.object);
			}
		};
		
		//
		// Formats a number with thousand separators so it's easier to read
		//
		// @param  args object An object consisting of:
		//                      o object
		//                      o number
		//                      o unitspre
		//                      o unitspost
		//                      o point
		//                      o thousand
		//                      o formatter
		// OR
		//
		// THESE ARE OLDER ARGS:
		//
		// @param  object obj The chart object
		// @param  integer num The number to format
		// @param  string      The (optional) string to prepend to the string
		// @param  string      The (optional) string to append to the string
		// @return string      The formatted number
		//
		DxChart.numberFormat = function (args) {
			var i;
			var prepend = args.unitspre ? String(args.unitspre) : "";
			var append = args.unitspost ? String(args.unitspost) : "";
			var output = "";
			var vdecimal = "";
			var decimal_seperator = typeof args.point === "string" ? args.point : ".";
			var thousand_seperator =
			typeof args.thousand === "string" ? args.thousand : ",";
			RegExp.$1 = "";
			var i, j;
			
			if (typeof args.formatter === "function") {
				return args.formatter(args);
			}
			
			// Ignore the preformatted version of "1e-2"
			if (String(args.number).indexOf("e") > 0) {
				return String(prepend + String(args.number) + append);
			}
			
			// We need then number as a string
			args.number = String(args.number);
			
			// Take off the decimal part - we re-append it later
			if (args.number.indexOf(".") > 0) {
				var tmp = args.number;
				args.number = args.number.replace(/\.(.*)/, ""); // The front part of the number
				vdecimal = tmp.replace(/(.*)\.(.*)/, "$2"); // The decimal part of the number
			}
			
			// Thousand separator
			//var separator = arguments[1] ? String(arguments[1]) : ',';
			var seperator = thousand_seperator;
			
			// Work backwards adding the thousand separators
			//
			// ** i is a local variable at this poin **
			var foundPoint;
			for (var i = args.number.length - 1, j = 0; i >= 0; j++, i--) {
				var character = args.number.charAt(i);
				
				if (j % 3 == 0 && j != 0) {
					output += seperator;
				}
				
				//
				// Build the output
				//
				output += character;
			}
			
			//
			// Now need to reverse the string
			//
			var rev = output;
			output = "";
			for (var i = rev.length - 1; i >= 0; i--) {
				output += rev.charAt(i);
			}
			
			// Tidy up
			//output = output.replace(/^-,/, '-');
			if (output.indexOf("-" + args.thousand) == 0) {
				output = "-" + output.substr(("-" + args.thousand).length);
			}
			
			// Reappend the decimal
			if (vdecimal.length) {
				output = output + decimal_seperator + vdecimal;
				vdecimal = "";
				RegExp.$1 = "";
			}
			
			// Minor bugette
			if (output.charAt(0) == "-") {
				output = output.replace(/-/, "");
				prepend = "-" + prepend;
			}
			
			// Get rid of leading commas
			output = output.replace(/^,+/, "");
			
			return prepend + output + append;
		};
		
		//
		// Draws horizontal coloured bars on something like the bar, line or scatter
		//
		// @param  args object An object consisting of:
		//                      o object
		//
		DxChart.drawBars = function () {
			var args = DxChart.getArgs(arguments, "object"),
			properties = args.object.properties,
			hbars = properties.backgroundHbars;
			
			if (hbars === null) {
				return;
			}
			
			//
			// Draws a horizontal bar
			//
			args.object.context.beginPath();
			
			for (var i = 0, len = hbars.length; i < len; ++i) {
				var start = hbars[i][0];
				var length = hbars[i][1];
				var color = hbars[i][2];
				
				// Perform some bounds checking
				if (DxChart.isNull(start)) start = args.object.scale2.max;
				if (start > args.object.scale2.max) start = args.object.scale2.max;
				if (DxChart.isNull(length)) length = args.object.scale2.max - start;
				if (start + length > args.object.scale2.max)
				length = args.object.scale2.max - start;
				if (start + length < -1 * args.object.scale2.max)
				length = -1 * args.object.scale2.max - start;
				
				if (
					properties.xaxisPosition == "center" &&
					start == args.object.scale2.max &&
					length < args.object.scale2.max * -2
				) {
					length = args.object.scale2.max * -2;
				}
				
				//
				// Draw the bar
				//
				var x = properties.marginLeft;
				var y = args.object.getYCoord(start);
				var w =
				args.object.canvas.width -
				properties.marginLeft -
				properties.marginRight;
				var h = args.object.getYCoord(start + length) - y;
				
				// Accommodate Opera :-/
				if (
					DxChart.ISOPERA != -1 &&
					properties.xaxisPosition == "center" &&
					h < 0
				) {
					h *= -1;
					y = y - h;
				}
				
				//
				// Account for X axis at the top
				//
				if (properties.xaxisPosition == "top") {
					y = args.object.canvas.height - y;
					h *= -1;
				}
				
				args.object.context.fillStyle = DxChart.parseLinearGradientInfo(
					args.object,
					color,
					x,
					y,
					w,
					h
				);
				if (isNexacroRuntime)
				args.object.context.setElementFillStyle(args.object.context.fillStyle);
				args.object.context.fillRect(x, y, w, h);
			}
		};
		
		//
		// Draws in-graph labels.
		//
		// @param  args object An object consisting of:
		//                      o object
		// OR
		//
		// @param object obj The graph object
		//
		DxChart.drawInGraphLabels = function () {
			var args = DxChart.getArgs(arguments, "object");
			var properties = args.object.properties,
			labels = properties.labelsIngraph,
			labels_processed = [];
			
			// Defaults
			var fgcolor = "black",
			bgcolor = "white",
			direction = 1;
			
			if (!labels) {
				return;
			}
			
			// Get the text configuration
			var textInfo = DxChart.getTextInfo({
					object: args.object,
					prefix: "labelsIngraph",
				});
			
			//
			// Preprocess the labels array. Numbers are expanded
			//
			for (var i = 0, len = labels.length; i < len; i += 1) {
				if (typeof labels[i] === "number") {
					for (var j = 0; j < labels[i]; ++j) {
						labels_processed.push(null);
					}
				} else if (
					typeof labels[i] === "string" ||
					typeof labels[i] === "object"
				) {
					labels_processed.push(labels[i]);
				} else {
					labels_processed.push("");
				}
			}
			
			// Turn off any shadow
			DxChart.noShadow(args.object);
			var text_x, text_y;
			if (labels_processed && labels_processed.length > 0) {
				for (var i = 0, len = labels_processed.length; i < len; i += 1) {
					if (labels_processed[i]) {
						var coords = args.object.coords[i];
						
						if (coords && coords.length > 0) {
							var x =
							(args.object.type == "bar"
								? coords[0] + coords[2] / 2
								: coords[0]) + (properties.labelsIngraphOffsetX || 0);
							var y =
							(args.object.type == "bar"
								? coords[1] + coords[3] / 2
								: coords[1]) + (properties.labelsIngraphOffsetY || 0);
							var length =
							typeof labels_processed[i][4] === "number"
							? labels_processed[i][4]
							: 25;
							
							args.object.context.beginPath();
							args.object.context.fillStyle =
							properties.labelsIngraphBackgroundColor || "black";
							if (isNexacroRuntime)
							args.object.context.setElementFillStyle(
								args.object.context.fillStyle
							);
							args.object.context.strokeStyle =
							properties.labelsIngraphLineColor || "black";
							if (isNexacroRuntime)
							args.object.context.setElementStrokeStyle(
								args.object.context.strokeStyle
							);
							
							if (args.object.type === "bar") {
								//
								// X axis at the top
								//
								if (args.object.get("xaxisPosition") == "top") {
									length *= -1;
								}
								
								if (properties.variantValue == "dot") {
									args.object.context.moveTo(
										Math.round(x),
										args.object.coords[i][1] - 5
									);
									args.object.context.lineTo(
										Math.round(x),
										args.object.coords[i][1] - 5 - length
									);
									
									text_x = Math.round(x);
									text_y = args.object.coords[i][1] - 5 - length;
								} else if (properties.variantValue == "arrow") {
									args.object.context.moveTo(
										Math.round(x),
										args.object.coords[i][1] - 5
									);
									args.object.context.lineTo(
										Math.round(x),
										args.object.coords[i][1] - 5 - length
									);
									
									text_x = Math.round(x);
									text_y = args.object.coords[i][1] - 5 - length;
								} else {
									args.object.context.arc(Math.round(x), y, 2.5, 0, 6.28, 0);
									if (properties.labelsIngraphLabelTop === true) {
										args.object.context.moveTo(Math.round(x), y);
										args.object.context.lineTo(
											Math.round(x),
											args.object.coords[i][1] - 5 - length
										);
										text_x = Math.round(x);
										text_y = args.object.coords[i][1] - 5 - length;
									} else {
										args.object.context.moveTo(Math.round(x), y);
										args.object.context.lineTo(Math.round(x), y - length);
										text_x = Math.round(x);
										text_y = y - length;
									}
								}
								
								args.object.context.stroke();
								args.object.context.fill();
							} else {
								if (
									typeof labels_processed[i] == "object" &&
									typeof labels_processed[i][3] == "number" &&
									labels_processed[i][3] == -1
								) {
									// Draw an up arrow
									drawUpArrow(x, y);
									var valign = "top";
									
									text_x = x;
									text_y = y + 5 + length;
								} else {
									text_x = x;
									text_y = y - 5 - length;
									
									if (
										text_y < 5 &&
										(typeof labels_processed[i] === "string" ||
											typeof labels_processed[i][3] === "undefined")
									) {
										text_y = y + 5 + length;
										var valign = "top";
									}
									
									if (valign === "top") {
										/// Draw an down arrow
										drawUpArrow(x, y);
									} else {
										/// Draw an up arrow
										drawDownArrow(x, y);
									}
								}
								
								args.object.context.fill();
							}
							
							args.object.context.beginPath();
							
							// Foreground color
							if (
								typeof labels_processed[i] === "object" &&
								typeof labels_processed[i][1] === "string"
							) {
								args.object.context.fillStyle = labels_processed[i][1];
							} else {
								args.object.context.fillStyle = properties.labelsIngraphColor;
							}
							if (isNexacroRuntime)
							args.object.context.setElementFillStyle(
								args.object.context.fillStyle
							);
							var bound = args.object.properties.labelsIngraphTextBound;
							if (bound == null || bound == undefined) bound = true;
							DxChart.text({
									object: args.object,
									
									font: textInfo.font,
									size: textInfo.size,
									color: args.object.context.fillStyle || textInfo.color,
									bold: textInfo.bold,
									italic: textInfo.italic,
									
									x: text_x,
									y: text_y + (args.object.properties.textAccessible ? 2 : 0),
									
									text:
									typeof labels_processed[i] === "object" &&
									typeof labels_processed[i][0] === "string"
									? labels_processed[i][0]
									: labels_processed[i],
									valign: valign || "bottom",
									halign: "center",
									bounding: bound,
									"bounding.fill":
									typeof labels_processed[i] === "object" &&
									typeof labels_processed[i][2] === "string"
									? labels_processed[i][2]
									: "white",
									tag: "labels ingraph",
								});
							args.object.context.fill();
						}
						
						// Draws a down arrow
						function drawUpArrow(x, y) {
							args.object.context.moveTo(Math.round(x), y + 5);
							args.object.context.lineTo(Math.round(x), y + 5 + length);
							
							args.object.context.stroke();
							args.object.context.beginPath();
							
							// This draws the arrow
							args.object.context.moveTo(Math.round(x), y + 5);
							args.object.context.lineTo(Math.round(x) - 3, y + 10);
							args.object.context.lineTo(Math.round(x) + 3, y + 10);
							args.object.context.closePath();
						}
						
						// Draw an up arrow
						function drawDownArrow(x, y) {
							args.object.context.moveTo(Math.round(x), y - 5);
							args.object.context.lineTo(Math.round(x), y - 5 - length);
							
							args.object.context.stroke();
							args.object.context.beginPath();
							
							// This draws the arrow
							args.object.context.moveTo(Math.round(x), y - 5);
							args.object.context.lineTo(Math.round(x) - 3, y - 10);
							args.object.context.lineTo(Math.round(x) + 3, y - 10);
							args.object.context.closePath();
						}
						
						valign = undefined;
					}
				}
			}
		};
		
		//
		// This function hides the crosshairs coordinates. This function
		// has no arguments
		//
		DxChart.hideCrosshairCoords = function () {
			var div = DxChart.Registry.get("coordinates.coords.div");
			
			if (
				div &&
				((div.style && div.style.opacity == 1) || div.opacity == 1) &&
				div.__object__.get("crosshairsCoordsFadeout")
			) {
				if (isNexacroRuntime) {
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.9);
						},
						25
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.8);
						},
						50
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.7);
						},
						75
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.6);
						},
						100
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.5);
						},
						125
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.4);
						},
						150
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.3);
						},
						175
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.2);
						},
						200
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_opacity(0.1);
						},
						225
					);
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_visible(false);
						},
						275
					);
				} else {
					var style = DxChart.Registry.get("coordinates.coords.div").style;
					
					setTimeout(function () {
							style.opacity = 0.9;
						}, 25);
					setTimeout(function () {
							style.opacity = 0.8;
						}, 50);
					setTimeout(function () {
							style.opacity = 0.7;
						}, 75);
					setTimeout(function () {
							style.opacity = 0.6;
						}, 100);
					setTimeout(function () {
							style.opacity = 0.5;
						}, 125);
					setTimeout(function () {
							style.opacity = 0.4;
						}, 150);
					setTimeout(function () {
							style.opacity = 0.3;
						}, 175);
					setTimeout(function () {
							style.opacity = 0.2;
						}, 200);
					setTimeout(function () {
							style.opacity = 0.1;
						}, 225);
					setTimeout(function () {
							style.opacity = 0;
						}, 250);
					setTimeout(function () {
							style.display = "none";
						}, 275);
				}
			} else {
				if (isNexacroRuntime) {
					nexacro._OnceCallbackTimer.callonce(
						div._refform,
						function () {
							div.set_visible(false);
						},
						275
					);
				} else {
					var style = DxChart.Registry.get("coordinates.coords.div").style;
					setTimeout(function () {
							style.display = "none";
						}, 275);
				}
			}
		};
		
		//
		// Draws the3D axes/background
		//
		// @param  args object An object consisting of:
		//                      o object
		// OR
		//
		// @param object obj The chart object
		//
		DxChart.draw3DAxes = function () {
			var args = DxChart.getArgs(arguments, "object");
			var properties = args.object.properties;
			
			var marginLeft = args.object.marginLeft,
			marginRight = args.object.marginRight,
			marginTop = args.object.marginTop,
			marginBottom = args.object.marginBottom,
			xaxispos = properties.xaxisPosition,
			graphArea = args.object.canvas.height - marginTop - marginBottom,
			halfGraphArea = graphArea / 2,
			offsetx = properties.variantThreedOffsetX,
			offsety = properties.variantThreedOffsetY,
			xaxis = properties.variantThreedXaxis,
			yaxis = properties.variantThreedYaxis;
			
			//
			// Draw the 3D Y axis
			//
			if (yaxis) {
				DxChart.draw3DYAxis(args.object);
			}
			
			// X axis
			if (xaxis) {
				if (xaxispos === "center") {
					args.object.path(
						"b m % % l % % l % % l % % c s #aaa f %",
						marginLeft,
						marginTop + halfGraphArea,
						marginLeft + offsetx,
						marginTop + halfGraphArea - offsety,
						args.object.canvas.width - marginRight + offsetx,
						marginTop + halfGraphArea - offsety,
						args.object.canvas.width - marginRight,
						marginTop + halfGraphArea,
						properties.variantThreedXaxisColor
					);
				} else {
					if (args.object.type === "hbar") {
						var xaxisYCoord =
						args.object.canvas.height - args.object.properties.marginBottom;
					} else {
						var xaxisYCoord = args.object.getYCoord(0);
					}
					
					args.object.path(
						"m % % l % % l % % l % % c s #aaa f %",
						marginLeft,
						xaxisYCoord,
						marginLeft + offsetx,
						xaxisYCoord - offsety,
						args.object.canvas.width - marginRight + offsetx,
						xaxisYCoord - offsety,
						args.object.canvas.width - marginRight,
						xaxisYCoord,
						properties.variantThreedXaxisColor
					);
				}
			}
		};
		
		//
		// Draws the3D Y axis/background
		//
		// @param  args object An object consisting of:
		//                      o object
		// OR
		//
		// @param object obj The chart object
		//
		DxChart.draw3DYAxis = function (args) {
			var args = DxChart.getArgs(arguments, "object");
			var properties = args.object.properties;
			
			var marginLeft = args.object.marginLeft,
			marginRight = args.object.marginRight,
			marginTop = args.object.marginTop,
			marginBottom = args.object.marginBottom,
			xaxispos = properties.xaxisPosition,
			graphArea = args.object.canvas.height - marginTop - marginBottom,
			halfGraphArea = graphArea / 2,
			offsetx = properties.variantThreedOffsetX,
			offsety = properties.variantThreedOffsetY,
			yaxisFill = properties.variantThreedYaxisColor || "#ddd";
			
			// Y axis
			// Commented out the if condition because of drawing oddities
			//if (!properties.noaxes && !properties.noyaxis) {
			
			if (
				(args.object.type === "hbar" || args.object.type === "bar") &&
				properties.yaxisPosition === "center"
			) {
				var x =
				(args.object.canvas.width - marginLeft - marginRight) / 2 + marginLeft;
			} else if (
				(args.object.type === "hbar" || args.object.type === "bar") &&
				properties.yaxisPosition === "right"
			) {
				var x = args.object.canvas.width - marginRight;
			} else {
				var x = marginLeft;
			}
			
			args.object.path(
				"b m % % l % % l % % l % % s #aaa f % b", // Don't know the b at the end is needed
				x,
				marginTop,
				x + offsetx,
				marginTop - offsety,
				x + offsetx,
				args.object.canvas.height - marginBottom - offsety,
				x,
				args.object.canvas.height - marginBottom,
				properties.variantThreedYaxisColor
			);
			//}
		};
		
		//
		// Draws a filled rectangle with curvy corners
		//
		// @param  args object An object consisting of:
		//                      o context
		//                      o x
		//                      o y
		//                      o w
		//                      o h
		//                      o roundtl
		//                      o roundtr
		//                      o roundbl
		//                      o roundbr
		// OR
		//
		// @param context object The context
		// @param x       number The X coordinate (top left of the square)
		// @param y       number The Y coordinate (top left of the square)
		// @param w       number The width of the rectangle
		// @param h       number The height of the rectangle
		// @param         number The radius of the curved corners
		// @param         boolean Whether the top left corner is curvy
		// @param         boolean Whether the top right corner is curvy
		// @param         boolean Whether the bottom right corner is curvy
		// @param         boolean Whether the bottom left corner is curvy
		//
		DxChart.roundedRect = function () {
			var args = DxChart.getArgs(
				arguments,
				"context,x,y,width,height,radius,roundtl,roundtr,roundbl,roundbr"
			);
			
			// The corner radius
			var r = args.radius ? args.radius : 3;
			
			// Change the radius based on the smallest width or height
			r = Math.min(Math.min(args.width, args.height) / 2, args.radius);
			
			var r2 = r;
			
			// The corners
			var corner_tl = args.roundtl === false ? false : true,
			corner_tr = args.roundtr === false ? false : true,
			corner_bl = args.roundbl === false ? false : true,
			corner_br = args.roundbr === false ? false : true;
			
			args.context.beginPath();
			args.context.moveTo(args.x, args.y + r);
			
			if (corner_tl) {
				args.context.quadraticCurveTo(args.x, args.y, args.x + r, args.y);
			} else {
				args.context.lineTo(args.x, args.y);
				args.context.lineTo(args.x + r, args.y);
			}
			
			// Top right corner
			args.context.lineTo(args.x + args.width - r, args.y);
			if (corner_tr) {
				args.context.quadraticCurveTo(
					args.x + args.width,
					args.y,
					args.x + args.width,
					args.y + r
				);
			} else {
				args.context.lineTo(args.x + args.width, args.y);
				args.context.lineTo(args.x + args.width, args.y + r);
			}
			
			// Bottom right corner
			args.context.lineTo(args.x + args.width, args.y + args.height - r);
			if (corner_br) {
				args.context.quadraticCurveTo(
					args.x + args.width,
					args.y + args.height,
					args.x + args.width - r,
					args.y + args.height
				);
			} else {
				args.context.lineTo(args.x + args.width, args.y + args.height);
				args.context.lineTo(args.x + args.width - r, args.y + args.height);
			}
			
			// Bottom left corner
			args.context.lineTo(args.x + r, args.y + args.height);
			if (corner_bl) {
				args.context.quadraticCurveTo(
					args.x,
					args.y + args.height,
					args.x,
					args.y + args.height - r
				);
			} else {
				args.context.lineTo(args.x, args.y + args.height);
				args.context.lineTo(args.x, args.y + args.height - r);
			}
			
			args.context.closePath();
		};
		
		//
		// Adds an event handler
		//
		// @param  args object An object consisting of:
		//                      o object
		//                      o name
		//                      o func
		// OR
		//
		// @param object obj   The graph object
		// @param string event The name of the event, eg ontooltip
		// @param object func  The callback function
		//
		DxChart.addCustomEventListener = function () {
			var args = DxChart.getArgs(arguments, "object,name,func");
			
			// Initialise the events array if necessary
			if (typeof DxChart.events[args.object.uid] === "undefined") {
				DxChart.events[args.object.uid] = [];
			}
			
			// Prepend "on" if necessary
			if (args.name.substr(0, 2) !== "on") {
				args.name = "on" + args.name;
			}
			
			DxChart.events[args.object.uid].push([args.object, args.name, args.func]);
			
			return DxChart.events[args.object.uid].length - 1;
		};
		
		DxChart._fireEvent = function () {
			var args = DxChart.getArgs(arguments, "object,name");
			if (args.object && args.object.isDxChart) {
				if (args.object[args.name]) {
					args.object[args.name](args.object);
				}
				
				var uid = args.object.uid;
				if (
					typeof uid === "string" &&
					typeof DxChart.events === "object" &&
					typeof DxChart.events[uid] === "object" &&
					DxChart.events[uid].length > 0
				) {
					for (var j = 0; j < DxChart.events[uid].length; ++j) {
						if (
							DxChart.events[uid][j] &&
							DxChart.events[uid][j][1] === args.name
						) {
							DxChart.events[uid][j][2](args.object);
						}
					}
				}
			}
		};
		
		//
		// Clears all the custom event listeners that have been registered
		//
		// @param  args object An object consisting of:
		//                      o uid
		// OR
		//
		// @param    string Limits the clearing to this object UID
		//
		DxChart.removeAllCustomEventListeners = function () {
			var args = DxChart.getArgs(arguments, "uid");
			
			if (args.uid && DxChart.events[args.uid]) {
				DxChart.events[args.uid] = [];
			} else {
				DxChart.events = [];
				
				// Use the REG to iterate through all registered objects
				// and remove the DOM1 listeners
				DxChart.REG.iterate(function (obj) {
						if (obj.onclick) obj.onclick = null;
						if (obj.onmousemove) obj.onmousemove = null;
						if (obj.onmouseover) obj.onmouseover = null;
						if (obj.onmouseout) obj.onmouseout = null;
					});
			}
		};
		
		//
		// Clears a particular custom event listener
		//
		// @param object obj The graph object
		// @param number i   This is the index that is return by .addCustomEventListener()
		//
		DxChart.removeCustomEventListener = function () {
			var args = DxChart.getArgs(arguments, "object,index");
			
			if (
				typeof DxChart.events === "object" &&
				typeof DxChart.events[args.object.uid] === "object" &&
				typeof DxChart.events[args.object.uid][args.index] === "object"
			) {
				DxChart.events[args.object.uid][args.index] = null;
			}
		};
		
		DxChart._drawBackgroundImageCallback = function (object, img) {
			var properties = object.properties;
			
			var marginLeft = object.marginLeft || properties.marginLeft;
			var marginRight = object.marginRight || properties.marginRight;
			var marginTop = object.marginTop || properties.marginTop;
			var marginBottom = object.marginBottom || properties.marginBottom;
			var stretch = properties.backgroundImageStretch;
			var align = properties.backgroundImageAlign;
			var x, y;
			if (typeof align === "string") {
				if (align.indexOf("right") != -1) {
					x =
					object.canvas.width -
					(properties.backgroundImageW || img.width) -
					marginRight;
				} else {
					x = marginLeft;
				}
				
				if (align.indexOf("bottom") != -1) {
					y =
					object.canvas.height -
					(properties.backgroundImageH || img.height) -
					marginBottom;
				} else {
					y = marginTop;
				}
			} else {
				x = marginLeft || 25;
				y = marginTop || 25;
			}
			
			x =
			typeof properties.backgroundImageX === "number"
			? properties.backgroundImageX
			: x;
			y =
			typeof properties.backgroundImageY === "number"
			? properties.backgroundImageY
			: y;
			var w = stretch
			? object.canvas.width - marginLeft - marginRight
			: img.width;
			var h = stretch
			? object.canvas.height - marginTop - marginBottom
			: img.height;
			
			if (typeof properties.backgroundImageW === "number")
			w = properties.backgroundImageW;
			if (typeof properties.backgroundImageH === "number")
			h = properties.backgroundImageH;
			
			var oldAlpha = object.context.globalAlpha;
			object.context.globalAlpha = properties.backgroundImageAlpha;
			if (isNexacroRuntime)
			object.context.setElementGlobalAlpha(object.context.globalAlpha);
			object.context.drawImage(img, x, y, w, h);
			object.context.globalAlpha = oldAlpha;
			if (isNexacroRuntime)
			object.context.setElementGlobalAlpha(object.context.globalAlpha);
		};
		
		DxChart.drawBackgroundImage = function (args) {
			var args = DxChart.getArgs(arguments, "object");
			var properties = args.object.properties;
			var img;
			if (typeof properties.backgroundImage === "string") {
				var sUrl = args.object.get("backgroundImage");
				if (
					typeof args.object.canvas.__DxChart_background_image__ === "undefined"
				) {
					if (isNexacroRuntime) {
						img = {};
						if (!args.object.canvas._imgobj) {
							args.object.canvas._imgobj = {};
						}
						var _imageload_callback = function (url, w, h, imgnode) {
							args.object.__DxChart_background_image_loaded__ = true;
							img.width = w;
							img.height = h;
							img.imagewidth = w;
							img.imageheight = h;
							DxChart._drawBackgroundImageCallback(args.object, img);
						};
						img.src = sUrl;
						img.handle = nexacro._getImageObject(
							sUrl,
							_imageload_callback,
							this,
							"",
							false
						);
						//img.handle = nexacro._getImageObject(sUrl, _imageload_callback, this);
					} else {
						img = new Image();
						if (typeof nexacro != "undefined") {
							if (sUrl.substring(0, 4).toLowerCase() == "url(") {
								sUrl = sUrl.substring(5, sUrl.length - 2);
							}
							if (!sUrl || !sUrl.length) {
								return null;
							}
							sUrl = nexacro._getImageLocation(sUrl);
						}
						img.src = sUrl;
					}
					img.__object__ = args.object;
					img.__canvas__ = args.object.canvas;
					img.__context__ = args.object.context;
					args.object.canvas.__DxChart_background_image__ = img;
				} else {
					img = args.object.canvas.__DxChart_background_image__;
				}
				if (!isNexacroRuntime) {
					img.onload = function () {
						args.object.__DxChart_background_image_loaded__ = true;
						DxChart.clear(args.object.canvas);
						DxChart.redrawCanvas(args.object.canvas);
					};
					DxChart._drawBackgroundImageCallback(args.object, img);
				}
			}
		};
		
