				if (isNexacroRuntime) {
					boundingX = boundingX - 3;
					boundingW = boundingW + 4;
				}
				context.fillStyle = bounding_fill;
				if (isNexacroRuntime) context.setElementFillStyle(bounding_fill);
				context.fillRect(boundingX, boundingY, boundingW, boundingH);
				context.strokeStyle = bounding_stroke;
				if (isNexacroRuntime) context.setElementStrokeStyle(bounding_stroke);
				
				context.strokeRect(boundingX, boundingY, boundingW, boundingH);
				
