			DxChart.drawTrialMark_old = function (obj) {
				var context = obj.context;
				context.beginPath();
				var lw = context.lineWidth;
				var ss = context.strokeStyle;
				
				var cx = 20,
				cy = 20,
				r = 15;
				var point1 = DxChart.getRadiusEndPoint(
					cx,
					cy,
					DxChart.PI - DxChart.HALFPI / 3,
					r
				);
				var point2 = DxChart.getRadiusEndPoint(
					cx,
					cy,
					DxChart.TWOPI - DxChart.HALFPI / 3,
					r
				);
				
				context.strokeStyle = "#EA5826";
				context.lineWidth = 3;
				if (isNexacroRuntime) {
					context.setElementStrokeStyle(context.strokeStyle);
					context.setElementLineWidth(context.lineWidth);
				}
				context.beginPath();
				context.moveTo(point1[0], point1[1]);
				context.lineTo(point1[0], point1[1]);
				context.lineTo(cx - 3, cy - 2);
				context.lineTo(cx + 3, cy + 5);
				context.lineTo(point2[0], point2[1]);
				context.stroke();
				
				context.strokeStyle = "#229EFD";
				if (isNexacroRuntime) {
					context.setElementStrokeStyle(context.strokeStyle);
				}
				context.beginPath();
				context.arc(cx, cy, r, 0, DxChart.TWOPI);
				context.stroke();
				
				if (ss) {
					context.strokeStyle = ss;
					if (isNexacroRuntime) {
						context.setElementStrokeStyle(ss);
					}
				}
				if (lw) {
					context.lineWidth = lw;
					if (isNexacroRuntime) {
						context.setElementLineWidth(context.lineWidth);
					}
				}
			};
			
