			DxChart.checkLC = function () {
				// 라이선스 Check 로직
				//  1. 현재날짜 구함
				//  2. DxChart.randomKey를 random하게 생성(Lxxx)형태 - xxx는 1000~2000사이
				//  3. DxChart[DxChart.randomKey] = false;
				//  4. DxChartLicense에 있는 장보로 체크할 문장을 생성
				//
				//  5. 체크1 : 암호화 한것과 DxChartLicense의 키가 같은지 확인(위조여부 확인)
				//              틀리면 무조건 false
				//  6. 체크2 : bCheckLicenseSkip가 true인 경우 무조건 true
				//              틀리면 다음 체트로 진행
				//  7. 체크3 : 도메인 체크
				//              틀리면 무조건 false
				//  8. 체크4 : 기간 체트  - "unlimit"인 경우 true
				//              틀리면 다음 체트로 진행
				//  9. 체크5 : 기간 체트  - 오늘이 기간안에 있는 경우 true
				//
				//  **  DxChart[DxChart.randomKey] 를 확인 하고 표시여부 결정(true: 비표시, false : 표시)
				
				var objDate = new Date();
				var sDate =
				objDate.getFullYear() +
				(objDate.getMonth() + 1 + "").padLeft(2, "0") +
				(objDate.getDate() + "").padLeft(2, "0");
				// Runtime일때 xadl로딩이전에 URL을 가져오지 못하는 문제로 두번 호출되는 현상 처리용
				trace("=======================================START");
				trace("1 : DxChart.randomKey=["+DxChart.randomKey+"]")
				if(!DxChart.randomKey)
				{
					DxChart.randomKey = "L" + DxChart.random(1000, 2000);
					trace("2 : DxChart.randomKey=["+DxChart.randomKey+"]")
					
					if(isNexacroRuntime)
					{
						DxChart[DxChart.randomKey] = -99;  // Runtime인 경우, 
					trace("3 : DxChart[DxChart.randomKey]=["+DxChart[DxChart.randomKey]+"]")
						return; 	
					}
				}
				trace("=======================================END");
				DxChart[DxChart.randomKey] = false;
				//DxChart.LC = false;
				
				var h;
				var bCheck = true;
				var bCheckLicenseSkip = false;
				//Jkkim 2024-02-01
				if (typeof DxChartLicense != "undefined") {
					var sep = "|"; //String.fromCharCode(30);
					var lh =
					DxChartLicense.Customer +
					sep +
					DxChartLicense.Project +
					sep +
					DxChartLicense.Domain +
					sep +
					DxChartLicense.Expired;
					
					// skip 값이 세팅이 되어 있으면, 라이선스 체크를 하지 않는다.
					if (DxChartLicense.skip) {
						lh = lh + sep + DxChartLicense.skip;
						bCheckLicenseSkip = true;
					}
					
					// AES암호화를 위한 key값을 얻는다.
					DxChart.genKey();
					
					// 서비스URL을 추출한다.
					if (isNexacroRuntime || !window.location) {
						if (!nexacro.getApplication()) {
							bCheck = false;
						}
						var url =
						bCheck == false
						? ""
						: nexacro._project_url || nexacro.getApplication().xadl;												
						url = url.toLowerCase();
						if (!url) url = "";
						if (url.indexOf("http") < 0) DxChart[DxChart.randomKey] = false; //DxChart.LC = false;
						var sUrl = url.split("/")[2];
						if (!sUrl) sUrl = "";
						h = sUrl.split(":")[0];
					}  else {
						h = window.location.hostname;
					}
					trace("h=["+h+"]");
					trace("lh=["+lh+"]");
					// DxChartLicense에서 얻은 정보로 문장으로 만들어 진 것을 암호화한다.(AES방식)
					var orgCode = DxChart.encryptAES(lh);
					var code = orgCode;
					var sep2 = "^"; //String.fromCharCode(28);
					var sep3 = "*";
					
					// 암호화된 것 중에 "+","=" 를 다른 문자로 대체
					code = code.replace(/\+/g, sep2).replace(/\=/g, sep3);
					
					// 체크1 : 암호화 한것과 DxChartLicense의 키가 같은지 확인(위조여부 확인)
					if (bCheck == true && code == DxChartLicense.License) {
						// 체크2 : bCheckLicenseSkip가 true인 경우 무조건 true
						if (bCheckLicenseSkip) {
							DxChart[DxChart.randomKey] = true;
						} else {
							// 체크3 : 도메인 체크
							var ah = DxChartLicense.Domain;
							if (ah.indexOf(h) >= 0) {
								// 체크4 : 기간 체트  - "unlimit"인 경우 true
								if (DxChartLicense.Expired == "unlimit") {
									//DxChart.LC = true;
									DxChart[DxChart.randomKey] = true;
								} else {
									// 체크5 : 기간 체트  - 오늘이 기간안에 있는 경우 true
									var date1 = new Date(
										parseInt(DxChartLicense.Expired.substr(0, 4)),
										parseInt(DxChartLicense.Expired.substr(4, 2)) - 1,
										parseInt(DxChartLicense.Expired.substr(6, 2)),
										23,
										59,
										59,
										9,
										999
									);
									var date2 = new Date();
									if (date1.getTime() > date2.getTime()) {
										//DxChart.LC = true;
										DxChart[DxChart.randomKey] = true;
									}
								}
							}
						}
					}
				}
				trace("FINAL :  DxChart[DxChart.randomKey]=["+DxChart[DxChart.randomKey]+"]");
			};
			
			
			// //skip체크 완전 제거후 리팩토링 Jkkim 2025-08-27
