  DxChart._replaceTouchEvent = function (e, obj) {
    if (e.type && e.type.indexOf("touch") >= 0) {
      var te = e.targetTouches;
      var sve = e;
      if (te && te[0]) {
        var tete = te[0];
        for (var xx in tete) {
          e[xx] = tete[xx];
        }
        e.offsetX = e.pageX;
        e.offsetY = e.pageY;
        if (!e.target) e.target = obj;
        e.offsetLeft = e.offsetTop = 0;
        e.type = sve.type;
      }
    }
    return e;
  };

