  DxChart.chartInstances = {}; // canvas별 차트 및 상태 관리

  DxChart.resizeCanvasToDisplaySize = function (canvas) {
    if (!canvas) return;

    // IE 및 Nexacro 호환을 위한 유효한 부모 찾기 함수
    function findValidParent(element) {
      var current = element.parentElement;
      var validParent = null;

      while (current && current.nodeType === 1) {
        var display = current.currentStyle
          ? current.currentStyle.display
          : window.getComputedStyle(current).display;
        var height = current.offsetHeight;

        // display 속성이 none이 아니고, 높이가 0보다 크면 유효한 부모로 설정
        if (display !== "none" && height > 0) {
          validParent = current;
          break;
        }

        current = current.parentElement;
      }
      return validParent;
    }

    var validParent = findValidParent(canvas);
    if (!validParent) return;

    var parentWidth = Math.floor(validParent.clientWidth);
    var parentHeight = Math.floor(validParent.clientHeight);

    if (canvas.width !== parentWidth || canvas.height !== parentHeight) {
      canvas.width = parentWidth;
      canvas.height = parentHeight;

      canvas.style.width = parentWidth + "px";
      canvas.style.height = parentHeight + "px";

      var MAX_HEIGHT = 350;
      if (canvas.height > MAX_HEIGHT) {
        canvas.height = MAX_HEIGHT;
        canvas.style.height = MAX_HEIGHT + "px";
      }
    }
  };

  DxChart.updateChart = function (obj) {
    var canvas = obj.canvas;
    if (!canvas) return;

    var canvasData = DxChart.chartInstances[canvas.id];
    if (!canvasData) {
      return;
    }

    if (canvasData.isResizing) {
      return;
    }

    canvasData.isResizing = true;

    try {
      //DxChart.resizeCanvasToDisplaySize(canvas);

      for (var i = 0; i < canvasData.charts.length; i++) {
        DxChart.redrawCanvas(canvas, true);
      }
    } catch (error) {
    } finally {
      canvasData.isResizing = false;
    }
  };

  DxChart.setupResponsiveCanvas = function (obj, conf) {
    if (!obj || !obj.canvas || !obj.canvas.id || obj.firstDraw == true) return;

    var canvas = obj.canvas;

    if (
      conf &&
      conf.options &&
      (conf.options.responsiveOff || conf.responsiveOff)
    ) {
      return;
    }

    if (!DxChart.chartInstances[canvas.id]) {
      DxChart.chartInstances[canvas.id] = { charts: [], isResizing: false };
    }

    var canvasData = DxChart.chartInstances[canvas.id];

    if (canvasData.charts.indexOf(obj.id) === -1) {
      canvasData.charts.push(obj.id);
    }

    var resizeTimeout = null;

    function resizeHandler() {
      if (resizeTimeout) {
        clearTimeout(resizeTimeout);
      }

      resizeTimeout = setTimeout(function () {
        DxChart.updateChart(obj);
      }, 200);
    }

    DxChart.updateChart(obj);

    if (!canvas.__resizeHandlerAdded) {
      canvas.__resizeHandlerAdded = true;
      if (window.addEventListener) {
        window.addEventListener("resize", resizeHandler);
      } else if (window.attachEvent) {
        window.attachEvent("onresize", resizeHandler);
      }
    }
  };

  /************V26 */
  //
  // This is the canvas mousemove event listener.
  //
  // @param object obj The chart object
  //
  DxChart.installCanvasMousemoveListener = function (obj) {
    var target = obj.canvas;
    if (isNexacroRuntime) {
      target = obj.canvas._refform;
    }
    if (!target.DxChart_mousemove_event_listener) {
      target.DxChart_mousemove_event_listener = function (e, e2) {
        e = DxChart._replaceTouchEvent(e, obj);

        if (isNexacroRuntime) {
          e = DxChart.FixEventObject(e, e2);
        }

        if (
          e.target.__object__ &&
          (e.target.__object__.type == "org" ||
            e.target.__object__.type == "tree" ||
            e.target.__object__.type == "map")
        ) {
          if (e.target.__object__.type == "map") {
            var objects = DxChart.REG.getObjectsByCanvasID(e.target.id);
            for (var i = 0; i < objects.length; ++i) {
              objects[i].onPointerMove(e);
            }
          } else {
            e.target.__object__.onPointerMove(e);
          }
        }
        //
        // For firefox add the window.event object
        //
        if (navigator.userAgent.indexOf("Firefox") >= 0) window.event = e;

        if (
          e.target.__object__ &&
          e.target.__object__.get("annotationValue") &&
          DxChart.annotating_canvas_onmousemove
        ) {
          DxChart.annotating_canvas_onmousemove(e);
          return;
        }

        //
        // Go through all the objects and check them to see if anything needs doing
        //
        var objects = DxChart.REG.getObjectsByXY(e);
        // Necessary to track which objects have had the mouseover
        // triggered on them
        var uids = [];
        if (objects && objects.length > 0) {
          for (var i = 0, len = objects.length; i < len; i += 1) {
            var obj = objects[i];
            var id = obj.id;

            // Record the uid
            uids[obj.uid] = true;
            if (typeof obj.getShape != "function") {
              continue;
            }

            var shape = obj.getShape(e);
            // If the object has changed (based on the UID) then
            // fire the prior objects mouseout event
            if (
              DxChart.last_mouseover_uid &&
              DxChart.last_mouseover_uid !== obj.uid
            ) {
              DxChart._fireEvent(DxChart.last_mouseover_object, "onmouseout");

              DxChart.last_mouseover_object.__mouseover_shape_index__ = null;
              DxChart.last_mouseover_object.__mouseover_shape__ = null;
              DxChart.last_mouseover_object = null;
              DxChart.last_mouseover_uid = null;
            }

            if (
              (!shape && typeof obj.__mouseover_shape_index__ === "number") ||
              (shape &&
                typeof obj.__mouseover_shape_index__ === "number" &&
                shape.index !== obj.__mouseover_shape_index__)
            ) {
              DxChart._fireEvent(obj, "onmouseout");
            }
            //
            // If the mouse is over a key element add the details
            // of it to the Registry
            //
            var mouseXY;
            if (obj.coords && obj.coords.key && obj.coords.key.length) {
              mouseXY = DxChart.getMouseXY(e);

              for (var i = 0, overkey = false; i < obj.coords.key.length; ++i) {
                if (
                  mouseXY[0] >= obj.coords.key[i][0] &&
                  mouseXY[0] <= obj.coords.key[i][0] + obj.coords.key[i][2] &&
                  mouseXY[1] >= obj.coords.key[i][1] &&
                  mouseXY[1] <= obj.coords.key[i][1] + obj.coords.key[i][3]
                ) {
                  DxChart.Registry.set("key-element", obj.coords.key[i]);
                  overkey = true;
                }

                if (!overkey) {
                  DxChart.Registry.set("key-element", null);
                }
              }
            } else if (obj.type == "gantt" || obj._isrange == true) {
              mouseXY = DxChart.getMouseXY(e);
            }
            // ================================================================================================ //
            // This facilitates the onmousemove facility
            // ================================================================================================ //
            var func = null,
              func2 = null;
            if (!func && typeof obj.onmousemove == "function") {
              func = obj.onmousemove;
            }
            //
            if (shape) {
              var index = shape.sequentialIndex;
              if (
                typeof obj["$" + index] === "object" &&
                typeof obj["$" + index].onmousemove == "function"
              ) {
                func2 = obj["$" + index].onmousemove;
              }
            }

            //
            // This bit saves the current pointer style if there isn't one already saved
            //
            if (
              shape &&
              (typeof func == "function" ||
                typeof func2 == "function" ||
                typeof obj.get("link") === "string")
            ) {
              if (obj.get("eventsMousemoveRevertto") == null) {
                if (isNexacroRuntime) {
                  obj.set("eventsMousemoveRevertto", e.target.cursor);
                } else {
                  obj.set("eventsMousemoveRevertto", e.target.style.cursor);
                }
              }

              if (typeof func == "function")
                DxChart.custom_events_mousemove_pointer = func(e, shape);
              if (typeof func2 == "function")
                DxChart.custom_events_mousemove_pointer =
                  DxChart.custom_events_mousemove_pointer || func2(e, shape);
              // Go through the DxChart.events array looking for more
              // event listeners
              if (
                typeof DxChart.events === "object" &&
                typeof DxChart.events[obj.uid] === "object"
              ) {
                for (var i in DxChart.events[obj.uid]) {
                  if (
                    typeof i === "string" &&
                    typeof DxChart.events[obj.uid][i] === "object" &&
                    DxChart.events[obj.uid][i][1] === "onmousemove" &&
                    typeof DxChart.events[obj.uid][i][2] === "function"
                  ) {
                    DxChart.events[obj.uid][i][2](obj);
                  }
                }
              }
              //return;
            } else if (typeof obj.get("eventsMousemoveRevertto") == "string") {
              DxChart.cursor.push("default");
              obj.set("eventsMousemoveRevertto", null);
            }
            // ======================================================
            // This bit of code facilitates the onmouseover event
            // ======================================================
            var func = null;
            if (!func && typeof obj.onmouseover === "function") {
              func = obj.onmouseover;
            }
            // Allow for individually index functions to be specified
            if (shape) {
              var index = shape.sequentialIndex;

              if (
                typeof obj["$" + index] == "object" &&
                typeof obj["$" + index].onmouseover == "function"
              ) {
                var func2 = obj["$" + index].onmouseover;
              }
            } else {
              obj.__mouseover_shape_index__ = null;
              DxChart.__mouseover_objects__ = [];
              DxChart.last_mouseover_uid = null;
              DxChart.last_mouseover_object = null;

              if (obj.type == "gantt") {
                // hsji
                DxChart.Registry.set("changing.ganttpoint", false);
                DxChart.evaluateCursor(e);
              }
            }

            if (typeof DxChart.__mouseover_objects__ === "undefined") {
              DxChart.__mouseover_objects__ = [];
              DxChart.last_mouseover_uid = null;
              DxChart.last_mouseover_object = null;
            }
            if (shape) {
              // 0620
              var treehighlight = DxChart.Registry.get("treehighlight");
              if (treehighlight && treehighlight.cube != shape.cube) {
                obj.removeHighlight(treehighlight);
              }

              if (obj.type == "tree" || obj.type == "map") {
                obj.highlight(shape);
              }

              if ((obj.__mouseover_shape_index__ === shape.index) === false) {
                obj.__mouseover_shape__ = shape;
                obj.__mouseover_shape_index__ = shape.index;
                DxChart.last_mouseover_uid = obj.uid;
                DxChart.last_mouseover_object = obj;
                DxChart.__mouseover_objects__.push(obj);

                if (func) func(e, shape);
                if (func2) func2(e, shape);

                // Go through the DxChart.events array looking for more
                // event listeners
                if (
                  typeof DxChart.events === "object" &&
                  typeof DxChart.events[obj.uid] === "object"
                ) {
                  for (var i in DxChart.events[obj.uid]) {
                    if (
                      typeof i === "string" &&
                      DxChart.events[obj.uid][i] &&
                      typeof DxChart.events[obj.uid][i] === "object" &&
                      DxChart.events[obj.uid][i][1] === "onmouseover" &&
                      typeof DxChart.events[obj.uid][i][2] === "function"
                    ) {
                      DxChart.events[obj.uid][i][2](obj);
                    }
                  }
                }
              }
            } else {
              obj.__mouseover_shape_index__ = null;
              DxChart.__mouseover_objects__ = [];
              DxChart.last_mouseover_uid = null;
              DxChart.last_mouseover_object = null;
            }
            var current_tooltip = DxChart.Registry.get("tooltip");
            // ================================================================================================ //
            // Tooltips
            // ================================================================================================ //
            var tooltips = obj.get("tooltips") || obj.get("tooltipsData");
            var tooltips_event = obj.get("tooltipsEvent");
            if (
              shape &&
              ((tooltips && tooltips[shape.index]) || shape.tooltip) &&
              tooltips_event.indexOf("mousemove") !== -1 &&
              (DxChart.isNull(current_tooltip) || // Is there a tooltip being shown?
                obj.uid != current_tooltip.__object__.uid || // Same object?
                current_tooltip.__index__ != shape.sequentialIndex || // Same datapiece index? [UPDATE ON 29/10/2019 TO TRY AND MATCH THE sequentialIndex]
                (current_tooltip &&
                  current_tooltip.__shape__ &&
                  typeof shape.dataset === "number" &&
                  shape.dataset != current_tooltip.__shape__.dataset)) // Different dataset index
            ) {
              //DxChart.clear(obj.canvas);
              //DxChart.redrawCanvas(obj.canvas);

              if (isNexacroRuntime) {
                DxChart.runtimeCanvasMouseupListener(obj, shape, e);
                //e.target._refform.DxChart_mouseup_event_listener(e.target, e);
              } else {
                DxChart.evaluateCursorNew(obj, e, shape, mouseXY);
                obj.canvas.DxChart_mouseup_event_listener(e);
                DxChart.clear(obj.canvas);
                DxChart.hideTooltip();
                DxChart.redraw();
              }
              return;
            }
            // ================================================================================================ //
            // Adjusting
            // ================================================================================================ //
            if (obj && obj.get("changeableValue")) {
              if (obj.type == "gantt" || obj._isrange === true) {
                // hsji
                DxChart.evaluateCursorNew(obj, e, shape, mouseXY);
              }
              obj.changing_mousemove(e, shape);
              return;
            }

            //sj.jo org chart drag & drop cursor add
            if (obj && obj.type == "org" && obj.get("itemDraggable")) {
              mouseXY = DxChart.getMouseXY(e);
              DxChart.evaluateCursorNew(obj, e, shape, mouseXY);
              return;
            }

            //
            // This facilitates breaking out of the loop when a shape has been found -
            // ie the cursor is over a shape an upper chart
            //
            if (shape || (obj.overChartArea && obj.overChartArea(e))) {
              break;
            }
            // 0620
            var treehighlight = DxChart.Registry.get("treehighlight");
            if (treehighlight && !shape) {
              treehighlight.obj.removeHighlight(treehighlight);
            }
          }
          //
          // For all objects that are NOT mouseover'ed, reset the
          // mouseover flag back to null
          //
          var objects = DxChart.REG.getObjectsByCanvasID(e.target.id);

          for (var i = 0; i < objects.length; ++i) {
            if (!uids[objects[i].uid]) {
              objects[i].__mouseover_shape_index__ = null;
            }
          }
          var current_tooltip = DxChart.Registry.get("tooltip");
          if (current_tooltip && !shape && obj) {
            DxChart._timerHideTooltip(obj);
          }
        } else {
          var objects = DxChart.REG.getObjectsByCanvasID(e.target.id);
          for (var i = 0; i < objects.length; i++) {
            if (typeof objects[i].__mouseover_shape_index__ === "number") {
              DxChart._fireEvent(objects[i], "onmouseout");
            }

            objects[i].__mouseover_shape_index__ = null;

            if (
              objects[i].type == "heatmap" &&
              DxChart._MouseDownFlag == true
            ) {
              var shape = objects[i].getShape(e);
              if (shape && objects[i].get("changeableValue")) {
                objects[i].changing_mousemove(e, shape);
              }
            }
          }

          DxChart.__mouseover_objects__ = [];
          DxChart.last_mouseover_uid = null;
          DxChart.last_mouseover_object = null;

          //hsji
          var current_tooltip = DxChart.Registry.get("tooltip");
          if (current_tooltip) {
            DxChart._timerHideTooltip(obj);
            DxChart.redrawCanvas(current_tooltip.__canvas__);
            //DxChart.hideTooltip();
          }
          var treehighlight = DxChart.Registry.get("treehighlight");
          if (treehighlight) {
            treehighlight.obj.removeHighlight(treehighlight);
          }
        }
        // ================================================================================================ //
        // Crosshairs
        // ================================================================================================ //
        if (
          e.target &&
          e.target.__object__ &&
          e.target.__object__.get("crosshairsUse")
        ) {
          DxChart.drawCrosshairs(e, e.target.__object__);
        }
        // ================================================================================================ //
        // Interactive key No LONGER REQUIRED
        // ================================================================================================ //
        //if (typeof InteractiveKey_line_mousemove == 'function') InteractiveKey_line_mousemove(e);
        //if (typeof InteractiveKey_pie_mousemove == 'function') InteractiveKey_pie_mousemove(e);

        // ================================================================================================ //
        // Annotating
        // ================================================================================================ //

        //
        // Determine the pointer
        //
        DxChart.evaluateCursor(e);
      };
      if (isNexacroRuntime) {
        obj.canvas.setEventHandler(
          "onmousemove",
          target.DxChart_mousemove_event_listener,
          target
        );
        obj.canvas.setEventHandler(
          "ontouchmove",
          target.DxChart_mousemove_event_listener,
          target
        );
      } else {
        target.addEventListener(
          "mousemove",
          target.DxChart_mousemove_event_listener,
          false
        );
        target.addEventListener(
          "touchmove",
          target.DxChart_mousemove_event_listener,
          false
        );
      }
    }
  };

  DxChart.FixEventObject = function (obj, evt) {
    var e = evt;
    if (e == undefined) return;
    if (e.clientx != undefined) {
      e.pageX = e.clientx;
      e.pageY = e.clienty;
      e.offsetX = e.pageX;
      e.offsetY = e.pageY;
    }
    //e.target = e.fromobject;
    e.target = obj;
    e.offsetLeft = e.offsetTop = 0;
    return e;
  };

  //
  // This is the canvas mousedown event listener.
  //
  // @param object obj The chart object
  //
  DxChart.installCanvasMousedownListener = function (obj) {
    var target = obj.canvas;
    if (isNexacroRuntime) {
      target = obj.canvas._refform;
    }
    if (!target.DxChart_mousedown_event_listener) {
      target.DxChart_mousedown_event_listener = function (e, e2) {
        DxChart._MouseDownFlag = true;
        e = DxChart._replaceTouchEvent(e, obj);

        if (isNexacroRuntime) {
          e = DxChart.FixEventObject(e, e2);
        }

        if (
          e.target.__object__ &&
          (e.target.__object__.type == "org" ||
            e.target.__object__.type == "tree" ||
            e.target.__object__.type == "map")
        ) {
          if (e.target.__object__.type == "map") {
            var objects = DxChart.REG.getObjectsByCanvasID(e.target.id);
            for (var i = 0; i < objects.length; ++i) {
              objects[i].onPointerDown(e);
            }
          } else {
            e.target.__object__.onPointerDown(e);
          }
        }
        //
        // For firefox add the window.event object
        //
        if (navigator.userAgent.indexOf("Firefox") >= 0) window.event = e;

        //
        // Annotating
        //
        if (
          e.target.__object__ &&
          e.target.__object__.get("annotationValue") &&
          DxChart.annotating_canvas_onmousedown
        ) {
          DxChart.annotating_canvas_onmousedown(e);
          return;
        }

        var obj = DxChart.REG.getObjectByXY(e);

        if (obj) {
          var id = obj.id;
          //
          // Handle changing for all object types
          //
          if (obj && obj.isDxChart && obj.get("changeableValue")) {
            var obj = DxChart.REG.getObjectByXY(e);

            if (obj && obj.isDxChart) {
              switch (obj.type) {
                case "bar":
                  var shape = obj.getShapeByX(e);
                  break;
                case "gantt":
                  var shape = obj.getShape(e);

                  if (shape) {
                    var data =
                      typeof obj.data[shape.dataset] === "object" &&
                      obj.data[shape.dataset][shape.index] &&
                      obj.data[shape.dataset][shape.index].start
                        ? obj.data[shape.dataset][shape.index]
                        : obj.data[shape.dataset];

                    var mouseXY = DxChart.getMouseXY(e);

                    DxChart.Registry.set("changing.gantt", {
                      dataset: shape.dataset,
                      index: shape.index,
                      object: obj,
                      mousex: mouseXY[0],
                      mousey: mouseXY[1],
                      event: data,
                      event_start: data.start,
                      event_duration: data.duration,
                      mode:
                        mouseXY[0] > shape.x + shape.width - 5
                          ? "resize"
                          : "move",
                      shape: shape,
                    });
                  }
                  break;
                case "line":
                  var shape = obj.getShape(e);
                  break;
                case "hbar":
                  var shape = obj.getShapeByY(e);
                  break;
                case "activity":
                  var shape = obj.getShape(e);
                  break;
                default:
                  var shape = null;
              }
              if (obj._isrange) {
                var shape = obj.getShape(e);
                if (shape) {
                  var mouseXY = DxChart.getMouseXY(e);
                  DxChart.Registry.set("changing.range", {
                    object: obj,
                    mousex: mouseXY[0],
                    mousey: mouseXY[1],
                    shape: shape,
                    sIndex: obj.owner.properties.rangeStartIndex,
                    eIndex: obj.owner.properties.rangeEndIndex,
                  });
                } else {
                  DxChart.Registry.set("changing.range", null);
                }
              }

              // Facilitate one click changing on the lline chart
              if (obj.type === "line" && obj.properties.changeableXonly) {
                var shape = obj.getShapeByX(e);
              }

              //
              // Added 30/9/2016
              // Now check the index in the changingLimitto property
              // If that property is an object and the appropriate index is
              // truthy then allow changing, otherwise don't.
              //
              if (
                DxChart.isNull(obj.properties.changeableOnly) ||
                typeof obj.properties.changeableOnly === "undefined" ||
                (DxChart.isArray(obj.properties.changeableOnly) &&
                  obj.isAdjustable &&
                  obj.isAdjustable(shape))
              ) {
                DxChart.Registry.set("changing.shape", shape);

                // Fire the onadjustbegin event
                DxChart._fireEvent(obj, "onchangebegin");

                DxChart.Registry.set("changing", obj);

                // Liberally redraw the canvas
                DxChart.clear(obj.canvas);
                DxChart.redraw();

                // Call the mousemove event listener so that the canvas
                // is adjusted even though the mouse isn't moved
                if (isNexacroRuntime) {
                  e.target._refform.DxChart_mousemove_event_listener(
                    e.target,
                    e
                  );
                } else {
                  obj.canvas.DxChart_mousemove_event_listener(e);
                }
              }
            }
          }

          if (obj.properties.tooltipsEffect !== "slide") {
            DxChart.clear(obj.canvas);
            DxChart.redraw();
          }
        }
      };
      if (isNexacroRuntime) {
        obj.canvas.setEventHandler(
          "onlbuttondown",
          target.DxChart_mousedown_event_listener,
          target
        );
      } else {
        target.addEventListener(
          "mousedown",
          target.DxChart_mousedown_event_listener,
          false
        );
        target.addEventListener(
          "touchstart",
          target.DxChart_mousedown_event_listener,
          false
        );
      }
    }
  };

  DxChart.runtimeCanvasMouseupListener = function (obj, shape, e) {
    DxChart.redrawCanvas(obj.canvas);
    DxChart.Registry.set("tooltip.shape", shape);
    var text = shape.tooltip;
    if (text) {
      DxChart.showTooltipRuntime({
        object: obj,
        text: text,
        x: 0,
        y: 0,
        index: shape.sequentialIndex,
        event: e,
      });
      // 615
      if (obj.type != "tree") {
        obj.highlight(shape);
      }
    }
  };

  //
  // This is the canvas mouseup event listener. It installs the mouseup event for the
  // canvas. The mouseup event then checks the relevant object.
  //
  // @param object obj The chart object
  //

  DxChart.installCanvasMouseupListener = function (obj) {
    var target = obj.canvas;
    if (isNexacroRuntime) {
      target = obj.canvas._refform;
    }
    if (!target.DxChart_mouseup_event_listener) {
      target.DxChart_mouseup_event_listener = function (e, e2) {
        DxChart._MouseDownFlag = false;
        if (e.type == "touchend") {
          DxChart.hideTooltip();
          DxChart.redrawCanvas(target);
        }
        e = DxChart._replaceTouchEvent(e, obj);

        if (isNexacroRuntime) {
          e = DxChart.FixEventObject(e, e2);
        }

        DxChart.Registry.set("changing.range", null);

        if (
          e.target.__object__ &&
          (e.target.__object__.type == "org" ||
            e.target.__object__.type == "tree" ||
            e.target.__object__.type == "map")
        ) {
          if (e.target.__object__.type == "map") {
            var objects = DxChart.REG.getObjectsByCanvasID(e.target.id);
            for (var i = 0; i < objects.length; ++i) {
              objects[i].onPointerUp(e);
            }
          } else {
            e.target.__object__.onPointerUp(e);
          }
        }
        //
        // For firefox add the window.event object
        //
        if (navigator.userAgent.indexOf("Firefox") >= 0) window.event = e;
        // *************************************************************************
        // Tooltips
        // *************************************************************************
        // This causes things at the edge of the chart area - eg line chart hotspots - not to fire because the
        // cursor is out of the chart area
        if (
          e.target.__object__ &&
          e.target.__object__.get("annotationValue") &&
          DxChart.annotating_window_onmouseup
        ) {
          DxChart.annotating_window_onmouseup(e);
          return;
        }
        var objects = DxChart.REG.getObjectsByXY(e);
        //var objects = DxChart.REG.getObjectsByCanvasID(e.target.id);
        if (objects) {
          if (objects.length == 0) {
            var objects2 = DxChart.REG.getObjectsByCanvasID(e.target.id);
            for (var i = 0; i < objects2.length; i++) {
              if (
                objects2[i].type == "heatmap" &&
                DxChart.Registry.get("changing.shape")
              ) {
                DxChart.Registry.set("changing.shape", null);
                DxChart.redrawCanvas(objects2[i].canvas);
              }
            }
          }
          for (var i = 0, len = objects.length; i < len; i += 1) {
            var obj = objects[i],
              id = objects[i].id;

            if (!DxChart.isNull(obj) && DxChart.showTooltip) {
              var shape = obj.getShape(e);

              if (shape && shape.tooltip) {
                var text = shape.tooltip;
                if (text) {
                  var type = shape.object.type;
                  if (!isNexacroRuntime) {
                    //DxChart.clear(obj.canvas);
                    DxChart.redrawCanvas(obj.canvas);
                    DxChart.Registry.set("tooltip.shape", shape);
                    // Note that tooltips are positioned at the pointer
                    // now; and thats done within the .tooltip() function
                    DxChart.showTooltip({
                      object: obj,
                      text: text,
                      x: 0,
                      y: 0,
                      index: shape.sequentialIndex,
                      event: e,
                    });

                    // 615
                    if (obj.type != "tree") {
                      obj.highlight(shape);
                    }
                  }

                  // Add the shape that triggered the tooltip
                  if (DxChart.Registry.get("tooltip")) {
                    DxChart.Registry.get("tooltip").__shape__ = shape;
                    DxChart.evaluateCursor(e, shape);
                  }

                  e.cancelBubble = true;
                  e.stopPropagation();
                  return false;
                }
              }
            }
            // =========================================================================
            // Adjusting
            // ========================================================================

            if (
              DxChart.Registry.get("changing") ||
              DxChart.Registry.get("changing.gantt")
            ) {
              //var obj = DxChart.Registry.get('changing');

              // If it's a line chart update the data_arr variable
              if (obj && obj.type === "line") {
                obj.data_arr = DxChart.arrayLinearize(obj.data);
              }

              DxChart._fireEvent(
                DxChart.Registry.get("changing"),
                "onadjustend"
              );
            }

            DxChart.Registry.set("changing", null);
            DxChart.Registry.set("changing.shape", null);
            DxChart.Registry.set("changing.gantt", null);
            DxChart.Registry.set("changing.range", null);

            //
            // If the mouse pointer is over a "front" chart this prevents charts behind it
            // from firing their events.
            //
            if (shape || (obj.overChartArea && obj.overChartArea(e))) {
              break;
            }
          }
          //                 } else {
          // 					 var objects = DxChart.REG.getObjectsByCanvasID(e.target.id);
          // 					   for (var i=0; i<objects.length; i++) {
          // 							if(objects[i].type == "heatmap" && DxChart.Registry.get('changing.shape')) {
          // 								DxChart.Registry.set('changing.shape', null);
          // 								DxChart.redrawCanvas(objects[i].canvas);
          // 							}
          // 						}
        }
      };
      if (isNexacroRuntime) {
        obj.canvas.setEventHandler(
          "onlbuttonup",
          target.DxChart_mouseup_event_listener,
          target
        );
      } else {
        target.addEventListener(
          "mouseup",
          target.DxChart_mouseup_event_listener,
          false
        );
        target.addEventListener(
          "touchend",
          target.DxChart_mouseup_event_listener,
          false
        );
      }
    }
  };
