  //onclick이벤트 개선 계산식 Jkkim 2025-12-29
  DxChart_isPointNearLine = function (obj, e, tolerance) {
    var mouseXY = DxChart.getMouseXY(e);
    var x = mouseXY[0];
    var y = mouseXY[1];

    var coords = obj.coords;
    if (!coords || coords.length < 2) return false;

    for (var i = 0; i < coords.length - 1; i++) {
      var x1 = coords[i][0],
        y1 = coords[i][1];
      var x2 = coords[i + 1][0],
        y2 = coords[i + 1][1];

      var dx = x2 - x1;
      var dy = y2 - y1;
      var len2 = dx * dx + dy * dy;
      if (len2 === 0) continue;

      var t = ((x - x1) * dx + (y - y1) * dy) / len2;
      t = Math.max(0, Math.min(1, t));

      var px = x1 + t * dx;
      var py = y1 + t * dy;

      var dist = Math.sqrt((x - px) * (x - px) + (y - py) * (y - py));

      if (dist <= tolerance) return true;
    }
    return false;
  };

  //onclick이벤트 개선 Click 이벤트 Jkkim 2025-12-29
  DxChart.installCanvasClickListener = function (obj) {
    var canvas = obj.canvas;
    var target = isNexacroRuntime ? canvas._refform : canvas;

    if (target.DxChart_click_event_listener) return;

    target.DxChart_click_event_listener = function (e, e2) {
      e = DxChart._replaceTouchEvent(e, obj);
      if (isNexacroRuntime) e = DxChart.FixEventObject(e, e2);

      // ==================================================
      // 0. canvas 영역 밖 클릭 차단
      // ==================================================
      var xy = DxChart.getMouseXY(e);
      if (
        xy[0] < 0 ||
        xy[1] < 0 ||
        xy[0] > canvas.width ||
        xy[1] > canvas.height
      ) {
        return;
      }

      var barHit = null;
      var lineHit = null;
      var otherHit = null;

      // ==================================================
      // 1. getObjectsByXY 기반 객체 수집
      //    (bar + 기타 차트용)
      // ==================================================
      var objects = DxChart.REG.getObjectsByXY(e);

      for (var i = 0; i < objects.length; i++) {
        var o = objects[i];
        if (typeof o.onclick !== "function") continue;

        var shape = o.getShape(e);

        // ===== LINE (point only, segment는 뒤에서 처리) =====
        if (o.type === "line" && !lineHit) {
          if (shape) {
            lineHit = { obj: o, shape: shape };
            continue;
          }
        }

        // ===== BAR =====
        if (o.type === "bar" && !lineHit && !barHit) {
          if (shape) {
            barHit = { obj: o, shape: shape };
            continue;
          }
        }

        // ===== OTHER CHART TYPES =====
        if (
          o.type !== "bar" &&
          o.type !== "line" &&
          !lineHit &&
          !barHit &&
          !otherHit &&
          shape
        ) {
          otherHit = { obj: o, shape: shape };
        }
      }

      // ==================================================
      // 2. LINE segment hit-test (Registry 전체 대상)
      // ==================================================
      if (!lineHit) {
        var lineObjects = DxChart.REG.getObjectsByCanvasID(canvas.id);
        for (var i = 0; i < lineObjects.length; i++) {
          var o = lineObjects[i];
          if (o.type !== "line") continue;
          if (typeof o.onclick !== "function") continue;

          var tolerance = isNexacroRuntime ? 7 : 5;
          if (DxChart_isPointNearLine(o, e, tolerance)) {
            lineHit = { obj: o, shape: null };
            break;
          }
        }
      }

      // ==================================================
      // 3. 실행 대상 결정
      // ==================================================
      var hit = lineHit || barHit || otherHit;
      if (!hit) return;

      var hitObj = hit.obj;
      var hitShape = hit.shape;

      // ==================================================
      // 4. object.onclick 실행
      // ==================================================
      hitObj.onclick(e, hitShape);

      // ==================================================
      // 5. DxChart.events (on 방식)
      // ==================================================
      if (DxChart.events && DxChart.events[hitObj.uid]) {
        for (var k in DxChart.events[hitObj.uid]) {
          var evt = DxChart.events[hitObj.uid][k];
          if (evt && evt[1] === "onclick" && typeof evt[2] === "function") {
            evt[2](hitObj);
          }
        }
      }

      // ==================================================
      // 6. index onclick ($0, $1 ...)
      // ==================================================
      if (
        hitShape &&
        typeof hitShape.sequentialIndex === "number" &&
        hitObj["$" + hitShape.sequentialIndex] &&
        typeof hitObj["$" + hitShape.sequentialIndex].onclick === "function"
      ) {
        hitObj["$" + hitShape.sequentialIndex].onclick(e, hitShape);
      }
    };

    // ==================================================
    // 이벤트 바인딩
    // ==================================================
    if (isNexacroRuntime) {
      canvas.setEventHandler(
        "onclick",
        target.DxChart_click_event_listener,
        target
      );
    } else {
      target.addEventListener(
        "click",
        target.DxChart_click_event_listener,
        false
      );
    }
  };

  DxChart.evaluateCursorNew = function (obj, e, shape, mouseXY) {
    if (shape && mouseXY) {
      var mode = mouseXY[0] > shape.x + shape.width - 5 ? "resize" : "move";
      if (obj._isrange === true) {
        mode = shape.mode == "m" ? "move" : "resize";
      }
      var canvas = obj.canvas;
      if (isNexacroRuntime) {
        canvas._refform.set_cursor(mode == "resize" ? "ew-resize" : "move");
      } else {
        //canvas.parentNode.style.cursor = (mode == 'resize'?"resize":"move");
        canvas.style.cursor = mode == "resize" ? "e-resize" : "move";
      }
      //sj.jo add - cursor for Gantt and Org Chart
      if (
        obj._isrange !== true ||
        (obj.type == "org" && obj.get("itemDraggable"))
      ) {
        DxChart.Registry.set("changing.ganttpoint", true);
      }
    }
    if (!shape) {
      var canvas = obj.canvas;
      if (isNexacroRuntime) {
        canvas._refform.set_cursor("default");
      } else {
        //canvas.parentNode.style.cursor = (mode == 'resize'?"resize":"move");
        canvas.style.cursor = "default";
      }
    }
  };

  DxChart.evaluateCursor = function (e, shape) {
    var canvas = e.target;
    var ganttPoint = DxChart.Registry.get("changing.ganttpoint");
    if (ganttPoint == true && shape) return;
    DxChart.Registry.set("changing.ganttpoint", false);
    if (isNexacroRuntime) {
      canvas._refform.set_cursor("default");
    } else {
      canvas.style.cursor = "default";
    }
  };

  //
  // This function handles the tooltip text being a string, function
  //
  // @param mixed tooltip This could be a string or a function. If it's a function it's called and
  //                       the return value is used as the tooltip text
  // @param numbr idx The index of the tooltip.
  //
  DxChart.parseTooltipText = function (tooltips, idx) {
    // No tooltips
    if (!tooltips) {
      return null;
    }

    // Get the tooltip text
    if (typeof tooltips == "function") {
      var text = tooltips(idx);

      // A single tooltip. Now with template support
    } else if (typeof tooltips == "string") {
      var text = tooltips;
    } else if (
      typeof tooltips === "object" &&
      typeof tooltips[idx] == "function"
    ) {
      var text = tooltips[idx](idx);
    } else if (
      typeof tooltips === "object" &&
      (DxChart.isNull(tooltips[idx]) || typeof tooltips[idx] === "undefined")
    ) {
      return null;
    } else if (typeof tooltips[idx] == "string" && tooltips[idx]) {
      var text = tooltips[idx];
    } else if (typeof tooltips[idx] == "number" && tooltips[idx]) {
      var text = tooltips[idx] + "";
    } else {
      var text = "";
    }

    if (typeof text === "undefined") {
      text = "";
    } else if (typeof text === "null") {
      text = "";
    }

    // Conditional in case the tooltip file isn't included
    return DxChart.getTooltipTextFromDIV
      ? DxChart.getTooltipTextFromDIV(text)
      : text;
  };

  //
  // Draw crosshairs if enabled
  //
  // @param object obj The graph object (from which we can get the context and canvas as required)
  //
  DxChart.drawCrosshairs = function (e, obj) {
    var width = obj.canvas.width,
      height = obj.canvas.height,
      mouseXY = DxChart.getMouseXY(e),
      x = mouseXY[0],
      y = mouseXY[1],
      marginLeft = obj.marginLeft,
      marginRight = obj.marginRight,
      marginTop = obj.marginTop,
      marginBottom = obj.marginBottom,
      prop = obj.properties,
      properties = obj.properties;

    DxChart.redrawCanvas(obj.canvas);

    if (
      x >= marginLeft &&
      y >= marginTop &&
      x <= width - marginRight &&
      y <= height - marginBottom
    ) {
      var lineWidth = properties.crosshairsLineWidth
        ? properties.crosshairsLineWidth
        : 1;
      obj.context.lineWidth = lineWidth ? lineWidth : 1;
      if (isNexacroRuntime)
        obj.context.setElementLineWidth(obj.context.lineWidth);

      obj.context.beginPath();
      obj.context.strokeStyle = properties.crosshairsColor;
      if (isNexacroRuntime)
        obj.context.setElementStrokeStyle(obj.context.strokeStyle);

      //
      // The crosshairsSnap option
      //
      if (properties.crosshairsSnap) {
        // Linear search for the closest point
        var point = null;
        var dist = null;
        var len = null;

        if (obj.type == "line") {
          for (var i = 0; i < obj.coords.length; ++i) {
            var length = DxChart.getHypLength(
              obj.coords[i][0],
              obj.coords[i][1],
              x,
              y
            );

            // Check the mouse X coordinate
            if (typeof dist != "number" || length < dist) {
              var point = i;
              var dist = length;
            }
          }

          x = obj.coords[point][0];
          y = obj.coords[point][1];

          // Get the dataset
          for (var dataset = 0; dataset < obj.coords2.length; ++dataset) {
            for (var point = 0; point < obj.coords2[dataset].length; ++point) {
              if (
                obj.coords2[dataset][point][0] == x &&
                obj.coords2[dataset][point][1] == y
              ) {
                obj.canvas.__crosshairs_snap_dataset__ = dataset;
                obj.canvas.__crosshairs_snap_point__ = point;
              }
            }
          }
        } else {
          for (var i = 0; i < obj.coords.length; ++i) {
            for (var j = 0; j < obj.coords[i].length; ++j) {
              // Check the mouse X coordinate
              var len = DxChart.getHypLength(
                obj.coords[i][j][0],
                obj.coords[i][j][1],
                x,
                y
              );

              if (typeof dist != "number" || len < dist) {
                var dataset = i;
                var point = j;
                var dist = len;
              }
            }
          }
          obj.canvas.__crosshairs_snap_dataset__ = dataset;
          obj.canvas.__crosshairs_snap_point__ = point;

          x = obj.coords[dataset][point][0];
          y = obj.coords[dataset][point][1];
        }
      }

      // Draw a vertical line
      if (properties.crosshairsVline) {
        obj.context.moveTo(Math.round(x), Math.round(marginTop));
        obj.context.lineTo(Math.round(x), Math.round(height - marginBottom));
      }

      // Draw a horizontal line
      if (properties.crosshairsHline) {
        obj.context.moveTo(Math.round(marginLeft), Math.round(y));
        obj.context.lineTo(Math.round(width - marginRight), Math.round(y));
      }

      obj.context.stroke();

      //
      // Need to show the coords?
      //
      if (obj.type == "scatter" && properties.crosshairsCoords) {
        var xCoord =
          ((x - marginLeft) / (width - marginLeft - marginRight)) *
            (properties.xaxisScaleMax - properties.xaxisScaleMin) +
          properties.xaxisScaleMin;
        xCoord = xCoord.toFixed(properties.yaxisScaleDecimals);
        var yCoord =
          obj.max -
          ((y - properties.marginTop) / (height - marginTop - marginBottom)) *
            (obj.max - obj.scale2.min);

        if (
          obj.type == "scatter" &&
          obj.properties.xaxisPosition === "center"
        ) {
          yCoord = (yCoord - obj.max / 2) * 2;
        }

        yCoord = yCoord.toFixed(properties.yaxisScaleDecimals);

        var div = DxChart.Registry.get("coordinates.coords.div");
        var mouseXY = DxChart.getMouseXY(e);
        var canvasXY = DxChart.getCanvasXY(obj.canvas);

        var position = properties.crosshairsPosition || "left";
        var bgcolor = properties.crosshairsBackgroundColor || "#ffffff";
        var color = properties.crosshairsTextColor || "#666666";
        var bdStyle = properties.crosshairsBorderStyle || "1px solid #dddddd";
        var bdRadius = properties.crosshairsborderRadius || "3px";
        var padding = properties.crosshairsPadding || "5px";
        var font =
          properties.crosshairsFontStyle || "10px Tahoma,Arial,Verdana";
        var fontObj = DxChart._parseFontInfo(font);

        if (!div) {
          if (isNexacroRuntime) {
            var form = obj.canvas.parent;
            var sid = "__DxChart_crosshair_";
            div = form.components[sid];
            div = new Div();
            div.init(sid, 0, 0, 0, 0, null, null);
            form.addChild(sid, div);
            div.show();
            div.set_visible(false);
            div.form.set_scrollbartype("none");
            div.set_background(bgcolor);
            div.set_border(bdStyle);
            div.set_borderRadius(bdRadius);
            var sta = new Static();
            sid = "__DxChart_crosshairstatic_";
            sta.init(sid, 0, 0, null, null, 0, 0);
            div.form.addChild(sid, sta);
            sta.show();
            sta.set_color(color);
            sta.set_visible(true);
            sta.set_padding(padding);
            //sta.set_fittocontents("both");
            div._sta = sta;
            div.__object__ = obj;
          } else {
            div = document.createElement("DIV");
            div.__object__ = obj;
            div.style.position = "absolute";
            div.style.backgroundColor = bgcolor;
            div.style.border = bdStyle;
            div.style.fontFamily = fontObj.face;
            div.style.fontSize = fontObj.size;
            div.style.padding = padding;
            div.style.opacity = 1;
            div.style.WebkitBorderRadius = bdRadius;
            div.style.borderRadius = bdRadius;
            div.style.MozBorderRadius = bdRadius;
            div.style.zIndex = 1500012;
            div.style.lineHeight = DxChart.ISIE ? "normal" : "initial";
            document.body.appendChild(div);
          }
          DxChart.Registry.set("coordinates.coords.div", div);
        }
        if (isNexacroRuntime) {
          div.set_background(bgcolor);
          div.set_border(bdStyle);
          div.set_borderRadius(bdRadius);
          div._sta.set_color(color);
          div._sta.set_padding(padding);
          div._sta.set_font(font);
        } else {
          div.style.backgroundColor = bgcolor;
          div.style.color = color;
          div.style.border = bdStyle;
          div.style.fontFamily = fontObj.face;
          div.style.fontSize = fontObj.size + "px";
          div.style.padding = padding;
          div.style.opacity = 1;
          div.style.WebkitBorderRadius = bdRadius;
          div.style.borderRadius = bdRadius;
          div.style.MozBorderRadius = bdRadius;
        }

        // org position

        // Use the formatter functions if defined. This allows the user to format them as they wish
        if (typeof properties.crosshairsCoordsFormatterX === "function") {
          xCoord = properties.crosshairsCoordsFormatterX({
            object: obj,
            value: parseInt(xCoord),
          });
        }
        if (typeof properties.crosshairsCoordsFormatterY === "function") {
          yCoord = properties.crosshairsCoordsFormatterY({
            object: obj,
            value: parseInt(yCoord),
          });
        }

        if (isNexacroRuntime) {
          var v = properties.crosshairsCoordsLabelsX + ": " + xCoord + "\n";
          v += properties.crosshairsCoordsLabelsY + ": " + yCoord + "\n";
          div.set_visible(true);
          div.bringToFront();

          var size = DxChart.measureText(
            v,
            fontObj.bold,
            fontObj.face,
            fontObj.size
          );
          div._sta.set_text(v);
          div.set_width(size[0] + 5);
          div.set_height(size[1] + 10);
        } else {
          div.innerHTML =
            '<span id="DxChart_crosshairsCoordsLabelsX">' +
            properties.crosshairsCoordsLabelsX +
            ":</span> " +
            xCoord +
            '<br><span id="DxChart_crosshairsCoordsLabelsY">' +
            properties.crosshairsCoordsLabelsY +
            ":</span> " +
            yCoord;
          // Change the color of the labels - don't use
          // inline styles because of CSP security errors
          document.getElementById(
            "DxChart_crosshairsCoordsLabelsX"
          ).style.color = color;
          document.getElementById(
            "DxChart_crosshairsCoordsLabelsY"
          ).style.color = color;

          obj.canvas.addEventListener(
            "mouseout",
            DxChart.hideCrosshairCoords,
            false
          );
        }

        if (isNexacroRuntime) {
          div.set_opacity(1);
          div.set_visible(true);
          div.bringToFront();
          var l = 0; //obj.canvas._refform.parent.getOffsetLeft();
          var t = 0; //obj.canvas._refform.parent.getOffsetTop();
          if (!properties.crosshairsCoordsFixed) {
            div.set_left(l + Math.max(2, e.pageX - div.getOffsetWidth() - 3));
            div.set_top(t + Math.max(2, e.pageY - div.getOffsetHeight() - 3));
          } else {
            var canvasw = obj.canvas.width;
            var canvash = obj.canvas.height;
            var w = div.getOffsetWidth();
            var h = div.getOffsetHeight();
            var ll, tt;
            if (position == "left") {
              ll = canvasXY[0] + marginLeft + 3;
            } else if (position == "center") {
              ll = (canvasw - w) / 2;
            } else if (position == "right") {
              ll = canvasw - w - marginRight;
            }
            tt = t + canvasXY[1] + marginTop + 3 - h;

            div.set_left(ll);
            div.set_top(t);
          }
        } else {
          div.style.opacity = 1;
          div.style.display = "inline";

          if (!properties.crosshairsCoordsFixed) {
            div.style.left = Math.max(2, e.pageX - div.offsetWidth - 3) + "px";
            div.style.top = Math.max(2, e.pageY - div.offsetHeight - 3) + "px";
          } else {
            var canvasw = obj.canvas.width;
            var canvash = obj.canvas.height;
            var w = parseInt(div.offsetWidth);
            var h = parseInt(div.offsetHeight);
            var l, t;
            if (position == "left") {
              l = canvasXY[0] + marginLeft + 3;
            } else if (position == "center") {
              l = (canvasw - w) / 2;
            } else if (position == "right") {
              l = canvasw - w - marginRight;
            }
            t = canvasXY[1] + marginTop - 3 - h;
            if (t < 0) t = 0;
            div.style.left = l + "px";
            div.style.top = t + "px";
          }
        }

        obj.canvas.__crosshairs_labels__ = div;
        obj.canvas.__crosshairs_x__ = xCoord;
        obj.canvas.__crosshairs_y__ = yCoord;
      } else if (properties.crosshairsCoords) {
        alert(
          "Showing crosshair coordinates is only supported on the Scatter chart"
        );
      }

      //
      // Fire the oncrosshairs custom event
      //
      DxChart._fireEvent(obj, "oncrosshairs");
    } else {
      DxChart.hideCrosshairCoords();
    }
  };

  //
  // Adds a mousemove event listener that highlights a segment based on th
  // mousemove event. Used in the Rose and the RScatter charts
  //
  //@param int segments The number of segments to allow
  //
  DxChart.allowSegmentHighlight = function (opt) {
    var obj = opt.object,
      count = opt.count,
      fill = opt.fill,
      stroke = opt.stroke;

    if (!DxChart.segmentHighlightFunction) {
      DxChart.segmentHighlightFunction = function (e) {
        var mouseXY = DxChart.getMouseXY(e);
        var angle = DxChart.getAngleByXY(
          obj.centerx,
          obj.centery,
          mouseXY[0],
          mouseXY[1]
        );

        angle += DxChart.HALFPI;

        if (angle > DxChart.TWOPI) {
          angle -= DxChart.TWOPI;
        }

        DxChart.redraw();

        var start = 0;
        var end = 0;
        var a = (Math.PI * 2) / count;

        //
        // Radius
        //
        var r = obj.radius;

        (function () {
          for (var i = 0; i < count; i += 1) {
            if (angle < a * (i + 1)) {
              start = i * a;
              end = (i + 1) * a;

              return;
            }
          }
        })();

        start -= DxChart.HALFPI;
        end -= DxChart.HALFPI;

        obj.path(
          "b m % % a % % % % % false c s % f %",
          obj.centerx,
          obj.centery,
          obj.centerx,
          obj.centery,
          r,
          start,
          end,
          stroke,
          fill
        );
      };
      obj.canvas.addEventListener(
        "mousemove",
        DxChart.segmentHighlightFunction,
        false
      );
    }
  };

