        setTimeout("if (obj = DxChart.Registry.get('contextmenu')) obj.style.opacity = 0.2", 50);
        setTimeout("if (obj = DxChart.Registry.get('contextmenu')) obj.style.opacity = 0.4", 100);
        setTimeout("if (obj = DxChart.Registry.get('contextmenu')) obj.style.opacity = 0.6", 150);
        setTimeout("if (obj = DxChart.Registry.get('contextmenu')) obj.style.opacity = 0.8", 200);
        setTimeout("if (obj = DxChart.Registry.get('contextmenu')) obj.style.opacity = 1", 250);

        // The fade in effect on the left gray bar
        setTimeout("if (obj = DxChart.Registry.get('contextmenu.bg')) obj.style.opacity = 0.2", 50);
        setTimeout("if (obj = DxChart.Registry.get('contextmenu.bg')) obj.style.opacity = 0.4", 100);
        setTimeout("if (obj = DxChart.Registry.get('contextmenu.bg')) obj.style.opacity = 0.6", 150);
        setTimeout("if (obj = DxChart.Registry.get('contextmenu.bg')) obj.style.opacity = 0.8", 200);
