				'<div id="tooltipdiv" name="tooltipdiv" cssclass="tooltipsCssClass" style="left:2px;top:2px;">\n';
				sHtml += "</div>\n";
				sHtml += '<script type="text/javascript">\n';
				sHtml += 'document.body.style.overflow = "hidden";\n';
