				sHtml += "  	if(elem) elem.style[v1] = v2; \n";
				sHtml += "  }catch(e){}\n";
				sHtml += "}\n";
				sHtml += "function setHtml(v) {\n";
				sHtml += "  div.innerHTML = v; \n";
				sHtml += "}\n";
				sHtml += "function getCStyle(v) {\n";
