	//
	// This function returns the pertinent value for a particular click (or other mouse event)
	// 
	// @param obj e The event object
	//
	this.getValue = function(e)
	{
		var mouseXY = DxChart.getMouseXY(e);
		var angle   = DxChart.getAngleByXY(
			this.centerx,
			this.centery,
			mouseXY[0],
			mouseXY[1]
		);

		// Adjust the angle because canvas angles
		// start at the east axis
		angle += DxChart.HALFPI;
		if (angle > DxChart.TWOPI) {
			angle -= DxChart.TWOPI;
		}

		// Calculate the value based on the angle and min/max values
		var value = ((angle / DxChart.TWOPI) * (this.max - this.min)) + this.min;

		// Ensure that the value is in range
		value = Math.max(value, this.min);
		value = Math.min(value, this.max);

		return value;
	};


	//
	// The getObjectByXY() worker method. Don't call this call:
	// 
	// DxChart.REG.getObjectByXY(e)
	// 
	// @param object e The event object
	//
	this.getObjectByXY = function(e)
	{
		var mouseXY = DxChart.getMouseXY(e),
			width   = this.width;

		// Work out the radius
		var radius = DxChart.getHypLength(
			this.centerx,
			this.centery,
			mouseXY[0],
			mouseXY[1]
		);

		if (radius > this.radius || radius < (this.radius * 0.25) ) {
			return null;
		}

		return this;
	};








	//
	// This method handles the changing calculation for when the mouse is moved
	// 
	// @param object e The event object
	//
	this.changing_mousemove = function(e)
	{
		var properties = this.properties;		
		//
		// Handle changing for the Bar
		//
		if (properties.changeableValue && DxChart.Registry.get('changing') && DxChart.Registry.get('changing').uid == this.uid) {

			var mouseXY = DxChart.getMouseXY(e);

			var radius = DxChart.getHypLength(
				this.centerx,
				this.centery,
				mouseXY[0],
				mouseXY[1]
			);

			var index  = this.getIndexByRadius(radius);
			
			// Store the index in the radius
			if (typeof DxChart.Registry.get('changing.index') !== 'number') {
				DxChart.Registry.set('changing.index', index);
				DxChart.addCustomEventListener(this, 'onchangeend', function ()
				{
					DxChart.Registry.set('changing.index', null);
				});
			} else {
				index = DxChart.Registry.get('changing.index')
			}

			if (typeof index === 'number') {
				this.value[index] = this.getValue(e);

				DxChart.clear(this.canvas);
				DxChart.redrawCanvas(this.canvas);
				DxChart._fireEvent(this, 'onchange');
			}
		}
	};








	//
	// Returns the relevant index of the relevant datapoint.
	// But only if it's in range.
	//
	// @param number radius The radius to check
	//
	this.getIndexByRadius = function(radius)
	{
		// Loop through the shapes to determine the correct shape
		for (var i=0; i<this.coords.length; ++i) {
			if (radius < this.coords[i].radiusOuter && radius > this.coords[i].radiusInner) {
				return i;
			}
		}
		
		return null;
	};








	//
	// This method returns the appropriate angle for a value
	// 
	// @param number value The value
	//
	this.getAngle = function(value)
	{
		// Higher than max
		if (value > this.max || value < this.min) {
			return null;
		}

		var angle = (((value - this.min) / (this.max - this.min)) * DxChart.TWOPI) - DxChart.HALFPI;

		if (value === this.max) angle -= 0.00001;
		if (value === this.min) angle += 0.00001;
		
		return angle;
	};








	//
	// Each object type has its own Highlight() function which highlights the appropriate shape
	//
	// @param object shape The shape to highlight
	//
	this.highlight = function(shape)
	{
		if(isNexacroRuntime) return;
		var properties = this.properties;		
		if (typeof properties.highlightStyle === 'function') {
			
			if (properties.tooltipsHighlight) {
				(properties.highlightStyle)(shape);
			}




		// Highlight all of the rings except this one - essentially an inverted highlight
		} else if (typeof properties.highlightStyle === 'string' && properties.highlightStyle === 'invert') {
		
			if (properties.tooltipsHighlight) {
				this.context.beginPath();
				
				for (var i=0; i<this.coords.length; ++i) {
					if (shape.index !== i) {
						this.pathBar(i);
					}
				}
			
				this.context.fillStyle   = properties.highlightFill;
				if(isNexacroRuntime) this.context.setElementFillStyle(properties.highlightFill);
				this.context.strokeStyle = properties.highlightStroke;
				if(isNexacroRuntime) this.context.setElementStrokeStyle(this.context.strokeStyle);
				this.context.stroke();
				this.context.fill();
			}




		// Regular highlighting
		} else {
			
			if (properties.tooltipsHighlight) {
				this.context.beginPath();
				
				this.pathBar(shape.index);
			
				this.context.fillStyle   = properties.highlightFill;
				if(isNexacroRuntime) this.context.setElementFillStyle(properties.highlightFill);
				this.context.strokeStyle = properties.highlightStroke;
				if(isNexacroRuntime) this.context.setElementStrokeStyle(this.context.strokeStyle);
				this.context.stroke();
				this.context.fill();
			}
		}




	};








	//
	// Paths a bar given an index but does not:
	//  o stroke
	//  o fill
	//  o issue a beginPath() call
	//  o issue a closePath() call
	//
	// Do NOT use when drawing the bars initially - the .coords array
	// must already be populated.
	//
	this.pathBar = function(index)
	{
		var properties = this.properties;		
		// Path the outer edge
		if(isNexacroRuntime) {
			this.context.arc(
				this.coords[index].x,
				this.coords[index].y,
				this.coords[index].radiusOuter,
				0 - DxChart.PI,
				this.coords[index].angleEnd2,
				false);
			this.context.lineTo(this.coords[index].x, this.coords[index].y);	
		} else {
			this.context.arc(
				this.coords[index].x,
				this.coords[index].y,
				this.coords[index].radiusOuter,
				0 - DxChart.HALFPI,
				this.coords[index].angleEnd,
				false);
		}
		
		// Get the center x/y coords of the end of the bar
		var xy = DxChart.getRadiusEndPoint(this.centerx,this.centery,this.coords[index].angleEnd,this.coords[index].radiusInner + ((this.coords[index].radiusOuter - this.coords[index].radiusInner) / 2));

		// Path the ending curved end if the ends are round
		if (properties.ends === 'round') {
			this.context.arc(
				xy[0],
				xy[1],
				this.width / 2,
				this.coords[index].angleEnd,
				this.coords[index].angleEnd + DxChart.PI,
				false);		
		}

		// Path the inner edge
		if(!isNexacroRuntime) {
			this.context.arc(
				this.coords[index].x,
				this.coords[index].y,
				this.coords[index].radiusInner,
				this.coords[index].angleEnd,
				this.coords[index].angleStart,
				true);
		}

		// Path the starting curved end if the ends are round
		if (properties.ends === 'round') {
			this.context.arc(
				this.centerx,
				this.centery - this.coords[index].radiusInner - ((this.coords[index].radiusOuter - this.coords[index].radiusInner) / 2),
				this.width / 2,
				DxChart.HALFPI,
				DxChart.PI  + DxChart.HALFPI,
				false);
		}
	};








	//
