	//
	// Meter Grow
	// 
	// This effect gradually increases the represented value
	// 
	// @param              An object of options - eg: {frames: 60}
	// @param function     An optional callback function
	//
	this.grow = function()
	{
		// Cancel any stop request if one is pending
		this.cancelStopAnimation();

		var obj = this;

		//
		// Convert the value to an array if its a number
		//
		if (typeof this.value === 'number') {
			this.value = [this.value];
		}

		//this.currentValue = this.currentValue || obj.min;
		if (DxChart.isNull(this.currentValue)) {
			
			this.currentValue=[];
			
			for (var i=0; i<this.value.length; ++i) {
				this.currentValue[i] = this.min;
			}
		}

		var opt      = arguments[0] || {},
			frames   = opt.frames || 30,
			frame    = 0,
			diff     = [],
			step     = [],
			callback = arguments[1] || function () {},
			initial  = [];
		
		// Set a few properties too by looping through the data
		for (var i=0; i<this.value.length; ++i) {
			diff[i] = this.value[i] - this.currentValue[i];
			step[i] = diff[i] / frames;
			initial[i] = this.currentValue[i];
		}



		function iterator ()
		{
			if (obj.stopAnimationRequested) {

				// Reset the flag
				obj.stopAnimationRequested = false;

				return;
			}




			for (var i=0; i<obj.value.length; ++i) {
				obj.value[i] = initial[i] + (frame * step[i]);
			}
			
			// Increment the frame
			frame++;

			DxChart.clear(obj.canvas);
			DxChart.redrawCanvas(obj.canvas);
		
			if (frame <= frames) {
				DxChart.Effects.updateCanvas(iterator, obj.canvas);
			} else {
				callback(obj);
			}
		}
		
		iterator();
		
		return this;
	};








	//
	// Couple of functions that allow you to control the
