  DxChart.setDefaultProperties(this, "yaxis");
  DxChart.setDefaultProperties(this, "text");
  DxChart.setDefaultProperties(this, "title");
  DxChart.setDefaultProperties(this, "variant");
  DxChart.setDefaultProperties(this, "shadow");
  DxChart.setDefaultProperties(this, "tooltips");
  DxChart.setDefaultProperties(this, "highlight");
  DxChart.setDefaultProperties(this, "key");
  DxChart.setDefaultProperties(this, "crosshairs");
  DxChart.setDefaultProperties(this, "line");
