  // 	var clickX = event.clientX + rect.left;
  //     var curIndex = Math.round((clickX - chart.properties.marginLeft) / stepSize);

  // 	// 범위를 넘으면 가장 큰 Index로 세팅
  // 	// Index의 갯수는 dataLength보다 하나 많음
  // 	// (curIndex의 최대값은 dataLength임. 0부터 시작하므로)
