	//
	// Use this function to reset the object to the post-constructor state. Eg reset colors if
	// need be etc
	//
	this.reset = function()
	{
	};








	//
	// This parses a single color value
	// 
	// @param string color    The color to look for a gradient in
	// @param radius OPTIONAL The start radius to start the gradient at.
	//                        If not suppllied the centerx value is used
	//
	this.parseSingleColorForGradient = function(color)
	{
		var properties = this.properties;	
		var radiusStart = arguments[1] || 0;

		if (!color || typeof color != 'string') {
			return color;
		}

		if (color.match(/^gradient\((.*)\)$/i)) {


			// Allow for JSON gradients
			if (color.match(/^gradient\(({.*})\)$/i)) {
				return DxChart.parseJSONGradient({object: this, def: RegExp.$1});
			}

			var parts = RegExp.$1.split(':');

			// Create the gradient
			var grad = this.context.createRadialGradient(
				this.centerx,
				this.centery,
				radiusStart,
				this.centerx,
				this.centery,
				this.radius
			);

			var diff = 1 / (parts.length - 1);

			grad.addColorStop(0, DxChart.trim(parts[0]));

			for (var j=1; j<parts.length; ++j) {
				grad.addColorStop(j * diff, DxChart.trim(parts[j]));
			}
		}

		return grad ? grad : color;
	};







