    //2024-11-05 Jkkim -> 단일데이터도 draw하도록 수정
	this.wave = function() {
		var properties = this.properties;
		this.cancelStopAnimation();
	
		var obj = this,
			opt = arguments[0] || {};
		opt.frames = opt.frames || 30;
		opt.startFrames = [];
		opt.counters = [];
	
		var framesperbar = opt.frames / 3,
			frame = -1,
			callback = arguments[1] || function () {},
			original = DxChart.arrayClone(obj.data),
			labelsAbove = properties.labelsAbove;
	
		//Jkkim 2025-02-05 false->true변경
		this.set('labelsAbove', true);
	
		//단일 데이터에 대한 설정 보장
		for (var i = 0, len = obj.data.length; i < len; i++) {
			opt.startFrames[i] = ((opt.frames / 2) / Math.max(1, (obj.data.length - 1))) * i;
			if (typeof obj.data[i] === 'object' && obj.data[i]) {
				opt.counters[i] = Array(obj.data[i].length).fill(0);
			} else {
				opt.counters[i] = 0;
			}
		}
		
	
		obj.draw();
		obj.set('xaxisScaleMax', obj.scale2.max);
		DxChart.clear(obj.canvas);
	
		var iterator = function() {
			if (obj.stopAnimationRequested) {
				obj.stopAnimationRequested = false;
				return;
			}
	
			frame++;
	
			for (var i = 0, len = obj.data.length; i < len; i++) {
				if (frame > opt.startFrames[i]) {
					if (typeof obj.data[i] === 'number') {
						obj.data[i] = Math.min(Math.abs(original[i]), Math.abs(original[i] * (opt.counters[i] / framesperbar)));
						opt.counters[i]++;
						if (original[i] < 0) obj.data[i] *= -1;
					} else if (Array.isArray(obj.data[i])) {
						for (var j = 0, len2 = obj.data[i].length; j < len2; j++) {
							obj.data[i][j] = Math.min(
								Math.abs(original[i][j]),
								Math.abs(original[i][j] * (opt.counters[i][j] / framesperbar))
							);
							opt.counters[i][j]++;
							if (original[i][j] < 0) obj.data[i][j] *= -1;
						}
					}
				} else {
					obj.data[i] = Array.isArray(obj.data[i])
						? DxChart.arrayPad([], obj.data[i].length, properties.xaxisScaleMin > 0 ? properties.xaxisScaleMin : 0)
						: (DxChart.isNull(obj.data[i]) ? null : (properties.xaxisScaleMin > 0 ? properties.xaxisScaleMin : 0));
				}
			}
	
			if (frame >= opt.frames) {
				if (labelsAbove) obj.set('labelsAbove', true);
				callback(obj);
			} else {
				DxChart.redrawCanvas(obj.canvas); // 매 프레임마다 canvas 리프레시
				DxChart.Effects.updateCanvas(iterator, obj.canvas);
			}
		};
	
		iterator();
		return this;
	};
	

	this.stopAnimation = function()
	{
		this.stopAnimationRequested = true;
	};

	this.cancelStopAnimation = function()
	{
		this.stopAnimationRequested = false;
	};

	this.isAdjustable = function(shape)
	{
		var properties = shape.object.properties;
		if (DxChart.isNull(properties.changeableOnly)) {
			return true;
		}
		if (DxChart.isArray(properties.changeableOnly) && properties.changeableOnly[shape.sequentialIndex]) {
			return true;
		}
		return false;
	};

