  this.drawAboveLabels = function () {
    var properties = this.properties;
    var units_pre = properties.labelsAboveUnitsPre,
      units_post = properties.labelsAboveUnitsPost,
      decimals = properties.labelsAboveDecimals,
      point = properties.labelsAbovePoint,
      thousand = properties.labelsAboveThousand,
      bgcolor = properties.labelsAboveBackground || "white",
      border =
        typeof properties.labelsAboveBorder === "boolean" ||
        typeof properties.labelsAboveBorder === "number"
          ? properties.labelsAboveBorder
          : true,
      bordercolor = properties.labelsAboveBorderStyleObj.color,
      borderwidth = properties.labelsAboveBorderStyleObj._width,
      borderstyle = properties.labelsAboveBorderStyleObj.style,
      offsety = properties.labelsAboveOffsetY,
      specific = properties.labelsAboveSpecific,
      formatter = properties.labelsAboveFormatter,
      data_arr = DxChart.arrayLinearize(this.orgData);
  
    // 라벨 스타일을 properties.labelsAboveFontstyle에서 가져오도록 수정
    var fontStyle = properties.labelsAboveFontStyleObj || {};
    var textFont = fontStyle.font || 'Arial'; // 폰트 이름
    var textSize = fontStyle.size || 12; // 폰트 크기
    var textColor = fontStyle.color || '#000000'; // 폰트 색상
    var textBold = fontStyle.bold || false; // 폰트 굵기
    var textItalic = fontStyle.italic || false; // 폰트 이탤릭
  
    offsety -= textSize;  // 폰트 크기에 따른 Y 오프셋 조정
  
    // Use this to 'reset' the drawing state
    this.context.beginPath();
  
    // Don't need to check that chart.labels.above is enabled here, it's been done already
    for (var i = 0, len = this.coords.length; i < len; i += 1) {
      var indexes = DxChart.sequentialIndexToGrouped(i, this.data),
        dataset = indexes[0],
        index = indexes[1],
        coords = this.coords[i];
      
      // Don't draw a label for null values
      if (DxChart.isNull(coords[1])) {
        continue;
      }
      if (this.hidden(dataset)) {
        continue;
      }
  
      DxChart.text({
        object: this,
        font: textFont,           // font 설정
        size: textSize,           // size 설정
        color: textColor,         // color 설정
        bold: textBold,           // bold 설정
        italic: textItalic,       // italic 설정
        x: coords[0] + properties.labelsAboveOffsetX,
        y: coords[1] + offsety,
        text:
          specific && specific[i]
            ? specific[i]
            : specific
            ? ""
            : DxChart.numberFormat({
                object: this,
                number:
                  typeof decimals === "number"
                    ? data_arr[i].toFixed(decimals)
                    : data_arr[i],
                value:
                  typeof decimals === "number"
                    ? data_arr[i].toFixed(decimals)
                    : data_arr[i],
                unitspre: units_pre,
                unitspost: units_post,
                point: point,
                thousand: thousand,
                formatter: formatter,
                index: index,
                dataset: dataset,
              }),
        valign: "center",
        halign: "center",
        bounding: border ? border : false,
        boundingFill: bgcolor ? bgcolor : "white",
        boundingStroke: bordercolor ? bordercolor : "rgba(0,0,0,0)",
        boundingLineWidth: borderwidth ? borderwidth : 1,
        tag: "labels.above",
      });
    }
  };
  




  //
  // Draw a curvy line.
  //
  this.drawCurvyLine = function (coords, color, lineWidth, index, fill) {
    var properties = this.properties;
    var yCoords = [];

    for (var i = 0; i < coords.length; ++i) {
      yCoords.push(coords[i][1]);
    }

    if (properties.filledUse) {
      this.context.beginPath();

      var xaxisY = this.getYCoord(properties.yaxisScaleMin);
      this.context.moveTo(coords[0][0], xaxisY);
      this.drawLineCurve(this.context, yCoords, color, index);

      if (properties.filledAccumulative && index > 0) {
        for (
          var i = this.coordsLineCurve[index - 1].length - 1;
          i >= 0;
          i -= 1
        ) {
          this.context.lineTo(
            this.coordsLineCurve[index - 1][i][0],
            this.coordsLineCurve[index - 1][i][1]
          );
        }
      } else {
        this.context.lineTo(coords[coords.length - 1][0], xaxisY);
      }
      if (isNexacroRuntime) {
        //this.context.setElementFillStyle(fill);
      }

      this.context.fill();
    }
    this.context.beginPath();
    // hsji
    this.context.moveTo(coords[0][0], coords[0][1]);
    this.drawLineCurve(this.context, yCoords, color, index);
    this.context.stroke();
  };

  this.getValue = function (arg) {
    var properties = this.properties;
    if (arg.length == 2) {
      var mouseX = arg[0];
      var mouseY = arg[1];
    } else {
      var mouseCoords = DxChart.getMouseXY(arg);
      var mouseX = mouseCoords[0];
      var mouseY = mouseCoords[1];
    }

    var obj = this;
    var xaxispos = properties.xaxisPosition;

    if (mouseY < properties.marginTop) {
      return xaxispos == "bottom" || xaxispos == "center" ? this.max : this.min;
    } else if (mouseY > this.canvas.height - properties.marginBottom) {
      return xaxispos == "bottom" ? this.min : this.max;
    }

    if (properties.xaxisPosition == "center") {
      var value =
        ((obj.chartArea / 2 - (mouseY - properties.marginTop)) /
          obj.chartArea) *
        (obj.max - obj.min);
      value *= 2;
      value > 0 ? (value += this.min) : (value -= this.min);
      return value;
    } else if (properties.xaxisPosition == "top") {
      var value =
        ((obj.chartArea - (mouseY - properties.marginTop)) / obj.chartArea) *
        (obj.max - obj.min);
      value = Math.abs(obj.max - value) * -1;
      return value;
    } else {
      var value =
        ((obj.chartArea - (mouseY - properties.marginTop)) / obj.chartArea) *
        (obj.max - obj.min);
      value += obj.min;
      return value;
    }
  };

  this.highlight = function (shape) {
    var properties = this.properties;
    if (properties.tooltipsHighlight) {
      if (typeof properties.highlightStyle === "function") {
        properties.highlightStyle(shape);

        // Inverted highlighting
      } else if (properties.highlightStyle === "invert") {
        this.context.save();
        this.context.beginPath();
        this.context.rect(
          this.marginLeft,
          this.marginTop,
          this.canvas.width - this.marginLeft - this.marginRight,
          this.canvas.height - this.marginTop - this.marginBottom
        );
        this.context.clip();

        this.context.beginPath();
        this.context.moveTo(shape.x, this.marginTop);
        this.context.arc(shape.x, shape.y, 25, 4.71, 4.72, true);
        this.context.lineTo(shape.x, this.marginTop);
        this.context.lineTo(
          this.canvas.width - this.marginRight,
          this.marginTop
        );
        this.context.lineTo(
          this.canvas.width - this.marginRight,
          this.canvas.height - this.marginBottom
        );
        this.context.lineTo(
          this.marginLeft,
          this.canvas.height - this.marginBottom
        );
        this.context.lineTo(this.marginLeft, this.marginTop);
        this.context.closePath();
        this.context.fillStyle = properties.highlightFill;
        if (isNexacroRuntime)
          this.context.setElementFillStyle(properties.highlightFill);
        this.context.fill();

        this.context.beginPath();
        this.context.arc(shape.x, shape.y, 25, 0, 6.29, false);
        this.context.strokeStyle = properties.highlightStroke;
        if (isNexacroRuntime)
          this.context.setElementStrokeStyle(properties.highlightStroke);
        this.context.stroke();

        this.context.restore();

        // Halo style highlighting
      } else if (properties.highlightStyle === "halo") {
        var obj = shape.object,
          color = properties.colors[shape.dataset];

        this.context.beginPath();
        this.context.arc(shape.x, shape.y, 13, 0, 6.283, false);
        this.context.fillStyle = "rgba(255,255,255,0.75)";
        if (isNexacroRuntime)
          this.context.setElementFillStyle("rgba(255,255,255,0.75)");
        this.context.fill();

        this.context.globalAlpha = 0.15;
        if (isNexacroRuntime) {
          this.context.setElementGlobalAlpha(0.15);
          this.context._globalAlphaFill = 0.15;
          this.context._globalAlphaStroke = 0.15;
        }

        this.context.beginPath();
        this.context.arc(shape.x, shape.y, 13, 0, 6.283, false);
        this.context.fillStyle = color;
        if (isNexacroRuntime) this.context.setElementFillStyle(color);
        this.context.fill();
        this.context.globalAlpha = 1;
        if (isNexacroRuntime) {
          this.context.setElementGlobalAlpha(1);
          this.context._globalAlphaFill = 1;
          this.context._globalAlphaStroke = 1;
        }

        this.context.beginPath();
        this.context.arc(shape.x, shape.y, 7, 0, 6.283, false);
        this.context.fillStyle = "white";
        if (isNexacroRuntime) this.context.setElementFillStyle("white");
        this.context.fill();

        this.context.beginPath();
        this.context.arc(shape.x, shape.y, 5, 0, 6.283, false);
        this.context.fillStyle = color;
        if (isNexacroRuntime) this.context.setElementFillStyle(color);
        this.context.fill();
      } else {
        DxChart.Highlight.point(this, shape);
      }
    }
  };

  this.getObjectByXY = function (e) {
    var properties = this.properties;
    var mouseXY = DxChart.getMouseXY(e);
    // The 5 is so that the cursor doesn't have to be over the graphArea to trigger the hotspot
    if (
      mouseXY[0] > this.marginLeft - 5 &&
      mouseXY[0] < this.canvas.width - this.marginRight + 5 &&
      mouseXY[1] > properties.marginTop - 5 &&
      mouseXY[1] < this.canvas.height - this.marginBottom + 5
    ) {
      return this;
    }
  };

  this.changing_mousemove = function (e) {
    var properties = this.properties;
    //
    // Handle changing for the Bar
    //
    if (
      properties.changeableValue &&
      DxChart.Registry.get("changing") &&
      DxChart.Registry.get("changing").uid == this.uid
    ) {
      // Rounding the value to the given number of decimals make the chart step
      var value = Number(this.getValue(e));
      var shape = DxChart.Registry.get("changing.shape");

      if (shape) {
        DxChart.Registry.set("changing.shape", shape);
        this.orgData[shape.dataset][shape.index] = Number(value);
        DxChart.redrawCanvas(e.target);
        DxChart._fireEvent(this, "onadjust");
      }
    }
  };

  this.getYCoord = function (value) {
    var properties = this.properties;
    if (arguments[1] === true) {
      var allowOutOfBounds = true;
    }

    if (typeof value != "number") {
      return null;
    }

    var y;
    var xaxispos = properties.xaxisPosition;

    if (xaxispos == "top") {
      // Account for negative numbers
      //if (value < 0) {
      //    value = Math.abs(value);
      //}

      y = ((value - this.min) / (this.max - this.min)) * this.chartArea;

      // Inverted Y labels
      if (properties.yaxisScaleInvert) {
        y = this.chartArea - y;
      }

      y = y + this.marginTop;
    } else if (xaxispos == "center") {
      y = ((value - this.min) / (this.max - this.min)) * (this.chartArea / 2);
      y = this.chartArea / 2 - y;
      y += this.marginTop;
    } else {
      if (
        !allowOutOfBounds &&
        (value < this.min || value > this.max) &&
        properties.outofbounds == false
      ) {
        return null;
      }

      y = ((value - this.min) / (this.max - this.min)) * this.chartArea;

      // Inverted Y labels
      if (properties.yaxisScaleInvert) {
        y = this.chartArea - y;
      }

      y = this.canvas.height - this.marginBottom - y;
    }

    return y;
  };


  this.getXCoord = function(value) {
    var properties = this.properties;
    var labels = properties.xaxisLabels;
    var canvasWidth = this.canvas.width - properties.marginLeft - properties.marginRight;
    var numberOfLabels = labels.length;
    var xaxispos = properties.xaxisPosition;
    var marginInner = properties.marginInner;

    // 문자열로 변환된 레이블 배열을 생성
    // var stringLabels = labels.map(label => String(label).trim());

          var stringLabels = [];
      for (var i = 0; i < labels.length; i++) {
          var label = labels[i];
          stringLabels.push(String(label).replace(/^\s+|\s+$/g, ''));
      }

    // // value가 포함된 레이블을 필터링하여 인덱스를 찾습니다
    // var matchingLabels = stringLabels.filter(label => value.includes(label));


        var matchingLabels = [];
    for (var i = 0; i < stringLabels.length; i++) {
        var label = stringLabels[i];
        if (value.indexOf(label) !== -1) { // value에 label이 포함되어 있는지 확인
            matchingLabels.push(label);
        }
    }


    // 일치하는 레이블이 없는 경우 null 반환
    if (matchingLabels.length === 0) {
        return null;
    }

    // 일치하는 첫 번째 레이블의 인덱스를 찾습니다
    var labelIndex = stringLabels.indexOf(matchingLabels[0]);

    // 레이블 인덱스가 유효한 경우에만 x 좌표를 계산합니다
    if (labelIndex === -1) {
        return null;
    }

    // Step Size 계산: 레이블의 수가 1보다 클 때만 유효
    var stepSize = (numberOfLabels > 1) ? (canvasWidth - marginInner) / (numberOfLabels - 1) : canvasWidth;

    var x;
    if (xaxispos === "top" || xaxispos === "bottom") {
        // x좌표 계산
        x = properties.marginLeft + (labelIndex * stepSize);
    } else if (xaxispos === "center") {
        // x축이 중앙에 있을 때
        x = properties.marginLeft + (labelIndex * stepSize) - (canvasWidth / 2);
    } else {
        // 기본 계산 방식
        x = properties.marginLeft + (labelIndex * stepSize);
    }

    // marginInner을 고려하여 x 좌표를 조정합니다
    x += marginInner / 2;

    return x;
};

