	//
	// Draws the needle of the odometer
	// 
	// @param number value The value to represent
	// @param string color The color of the needle
	// @param number       The OPTIONAL length of the needle
	//
	this.drawNeedle = function(value, color)
	{
		var properties = this.properties;
		// The optional length of the needle
		var length = arguments[2] ? arguments[2] : this.radius - properties.labelsMargin;

		if(length<21) length=21;

		// ===== First draw a grey background circle =====
		
		this.context.fillStyle = '#999999';
		if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);

		this.context.beginPath();
			this.context.moveTo(this.centerx, this.centery);
			this.context.arc(this.centerx, this.centery, 10, 0, DxChart.TWOPI, false);
			this.context.fill();
		this.context.closePath();

		this.context.fill();

		// ===============================================
		
		this.context.fillStyle = color;
		if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);
		this.context.strokeStyle = '#666666';
		if(isNexacroRuntime) this.context.setElementStrokeStyle(this.context.strokeStyle);

		// Draw the centre bit
		this.context.beginPath();
			this.context.moveTo(this.centerx, this.centery);
			this.context.arc(this.centerx, this.centery, 8, 0, DxChart.TWOPI, false);
			this.context.fill();
		this.context.closePath();
		
		this.context.stroke();
		this.context.fill();

		if (properties.needleType == 'pointer') {

			this.context.strokeStyle = color;
			if(isNexacroRuntime) this.context.setElementStrokeStyle(this.context.strokeStyle);
			this.context.lineWidth   = properties.needleWidth;
			if(isNexacroRuntime) this.context.setElementLineWidth(this.context.lineWidth);
			this.context.lineCap     = 'round';
			if(isNexacroRuntime) this.context.setElementLineCap(this.context.lineCap);
			this.context.lineJoin    = 'round';
			if(isNexacroRuntime) this.context.setElementLineJoin(this.context.lineJoin);

			// Draw the needle
			this.context.beginPath();
				// The trailing bit on the opposite side of the dial
				this.context.beginPath();
					this.context.moveTo(this.centerx, this.centery);
					
					if (properties.needleTail) {
						var sc = (((value / this.range) * 360) + 90) / (180 / DxChart.PI);
						
						if(isNexacroRuntime) {
							var x1 = this.centerx + (Math.cos(sc) * (20));
							var y1 = this.centery + (Math.sin(sc) * (20));
							this.context.lineTo(x1, y1);
							this.context.closePath();
							this.context.stroke();
							this.context.beginPath();
						} else {
							this.context.arc(this.centerx,
								   this.centery,
								   20,
									sc,
								   (((value / this.range) * 360) + 90 + 0.01) / (180 / DxChart.PI), // The 0.01 avoids a bug in ExCanvas and Chrome 6
								   false
								  );
						}
					}
				var sc = (((value / this.range) * 360) - 90) / (180 / DxChart.PI);
				if(isNexacroRuntime) {
					var x1 = this.centerx + (Math.cos(sc) * (length - 10));
					var y1 = this.centery + (Math.sin(sc) * (length - 10));
					this.context.moveTo(this.centerx, this.centery);
					this.context.lineTo(x1, y1);
					this.context.closePath();
					this.context.stroke();				
				} else {
					// Draw the long bit on the opposite side
					this.context.arc(this.centerx,
							this.centery,
							length - 10,
							sc,
							(((value / this.range) * 360) - 90 + 0.1 ) / (180 / DxChart.PI), // The 0.1 avoids a bug in ExCanvas and Chrome 6
							false
						   );
				}
			this.context.closePath();
			
			//this.context.stroke();
			//this.context.fill();
		

		} else if (properties.needleType == 'triangle') {

			this.context.lineWidth = 0.01;
			if(isNexacroRuntime) this.context.setElementLineWidth(this.context.lineWidth);
			this.context.lineEnd  = 'square';
			this.context.lineJoin = 'miter';
			if(isNexacroRuntime) this.context.setElementLineJoin(this.context.lineJoin);

			//
			// This draws the version of the pointer that becomes the border
			//
			this.context.beginPath();
			this.context.fillStyle = properties.needleTriangleBorder;
			
			if(isNexacroRuntime) {
				this.context.setElementLineWidth(2);
				this.context.setElementStrokeStyle(properties.needleTriangleBorder);
				this.context.setElementFillStyle(color);
				var sc = (((value / this.range) * 360)) / 57.3;
				var s1 = DxChart.getRadiusEndPoint(this.centerx, this.centery, sc, 11);
				
				sc = (((value / this.range) * 360) + 180) / 57.3;
				var s2 = DxChart.getRadiusEndPoint(this.centerx, this.centery, sc, 11);
				
				sc = (((value / this.range) * 360) - 90) / 57.3;
				var s3 = DxChart.getRadiusEndPoint(this.centerx, this.centery, sc, length - 5);
				
				this.path('b m % % l % % l % % l % % c f % s %',
					this.centerx, this.centery,
					s1[0],s1[1],
					s3[0],s3[1],
					s2[0],s2[1],
					color,
					properties.needleTriangleBorder
				);
				this.context.setElementLineWidth(0.01);
				this.context.beginPath();			
			} else {
				
				this.context.arc(this.centerx, this.centery, 11, (((value / this.range) * 360)) / 57.3, ((((value / this.range) * 360)) + 0.01) / 57.3, 0);
				this.context.arc(this.centerx, this.centery, 11, (((value / this.range) * 360) + 180) / 57.3, ((((value / this.range) * 360) + 180) + 0.01)/ 57.3, 0);
				this.context.arc(this.centerx, this.centery, length - 5, (((value / this.range) * 360) - 90) / 57.3, ((((value / this.range) * 360) - 90) / 57.3) + 0.01, 0);
			}
			this.context.closePath();
			this.context.fill();

			this.context.beginPath();
			this.context.arc(this.centerx, this.centery, 15, 0, DxChart.TWOPI, 0);
			this.context.closePath();
			this.context.fill();

			// This draws the pointer
			this.context.beginPath();
			this.context.strokeStyle = 'black';
			if(isNexacroRuntime) this.context.setElementStrokeStyle(this.context.strokeStyle);
			this.context.fillStyle = color;
			if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);
			this.context.arc(this.centerx, this.centery, 7, (((value / this.range) * 360)) / 57.3, ((((value / this.range) * 360)) + 0.01) / 57.3, 0);
			this.context.arc(this.centerx, this.centery, 7, (((value / this.range) * 360) + 180) / 57.3, ((((value / this.range) * 360) + 180) + 0.01)/ 57.3, 0);
			this.context.arc(this.centerx, this.centery, length - 13, (((value / this.range) * 360) - 90) / 57.3, ((((value / this.range) * 360) - 90) / 57.3) + 0.01, 0);
			this.context.closePath();
			this.context.stroke();
			this.context.fill();


			//
			// This is here to accommodate the MSIE/ExCanvas combo
			//
			this.context.beginPath();
			this.context.arc(this.centerx, this.centery, 7, 0, DxChart.TWOPI, 0);
			this.context.closePath();
			this.context.fill();
		}


		this.context.stroke();
		this.context.fill();

		// Draw the mini center circle
		this.context.beginPath();
		this.context.fillStyle = color;
		if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);
		this.context.arc(this.centerx, this.centery, properties.needleType == 'pointer' ? 7 : 12, 0.01, DxChart.TWOPI, false);
		this.context.fill();

		// This draws the arrow at the end of the line
		if (properties.needleHead && properties.needleType == 'pointer') {
			this.context.lineWidth = 1;
			if(isNexacroRuntime) this.context.setElementLineWidth(this.context.lineWidth);
			this.context.fillStyle = color;
			if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);

			// round, bevel, miter
			this.context.lineJoin = 'miter';
			if(isNexacroRuntime) this.context.setElementLineJoin(this.context.lineJoin);
			this.context.lineCap  = 'butt';
			if(isNexacroRuntime) this.context.setElementLineCap(this.context.lineCap);

			this.context.beginPath();
			
			if(isNexacroRuntime) {
				var sc = (((value / this.range) * 360) - 90) / 57.3;
				var x1 = this.centerx + (Math.cos(sc) * (length - 5));
				var y1 = this.centery + (Math.sin(sc) * (length - 5));
				sc = DxChart.toRadians( ((value / this.range) * 360) - (length < 60 ? 80 : 85) );
				var x2 = this.centerx + (Math.cos(sc) * (length - 20));
				var y2 = this.centery + (Math.sin(sc) * (length - 20));
				sc = DxChart.toRadians( ((value / this.range) * 360) - (length < 60 ? 100 : 95) );
				var x3 = this.centerx + (Math.cos(sc) * (length - 20));
				var y3 = this.centery + (Math.sin(sc) * (length - 20));
				this.context.moveTo(x1, y1);
				this.context.lineTo(x2, y2);
				this.context.lineTo(x3, y3);
	
			} else {
				this.context.arc(this.centerx, this.centery, length - 5, (((value / this.range) * 360) - 90) / 57.3, (((value / this.range) * 360) - 90 + 0.1) / 57.3, false);

				this.context.arc(this.centerx,
					   this.centery,
					   length - 20,
					   DxChart.toRadians( ((value / this.range) * 360) - (length < 60 ? 80 : 85) ),
					   DxChart.toRadians( ((value / this.range) * 360) - (length < 60 ? 100 : 95) ),
					   1);
			}
			this.context.closePath();
			this.context.fill();
			//this.context.stroke();
		}


		//
		// Draw a white circle at the centre
		//
		this.context.beginPath();
		this.context.fillStyle = 'gray';
		if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);
		this.context.moveTo(this.centerx, this.centery);
		this.context.arc(this.centerx,this.centery,2,0,6.2795,false);
		this.context.closePath();

		this.context.fill();
	};








	//
