			DxChart.text({object:this,font: textInfo.font, size: textInfo.size, color: textInfo.color, bold: textInfo.bold, italic: textInfo.italic,x:centerx + (0.951 * r ),y:centery - (0.309 * r),text:DxChart.numberFormat({object: this, number: (((end - start) * (2/10)) + start).toFixed(decimals), unitspre:units_pre, unitspost: units_post,point: point,thousand: thousand}),halign:'center',valign:'center',angle:72,tag: 'scale'});
			DxChart.text({object:this,font: textInfo.font, size: textInfo.size, color: textInfo.color, bold: textInfo.bold, italic: textInfo.italic,x:centerx + (0.949 * r),y:centery + (0.31 * r),text:DxChart.numberFormat({object: this, number: (((end - start) * (3/10)) + start).toFixed(decimals), unitspre: units_pre, unitspost: units_post,point: point,thousand: thousand}),halign:'center',valign:'center',angle:108,tag: 'scale'});
