	{
		var mouseXY = DxChart.getMouseXY(e)
		var angle   = DxChart.getAngleByXY(this.centerx, this.centery, mouseXY[0], mouseXY[1]);
			angle  += DxChart.HALFPI;
		
		if (mouseXY[0] >= this.centerx && mouseXY[1] <= this.centery) {
			angle -= DxChart.TWOPI;
		}

		var value = ((angle / DxChart.TWOPI) * (this.max - this.min)) + this.min;

		return value;
	};








