	//
	// Odo Grow
	// 
	// This effect gradually increases the represented value
	// 
	// @param              An object of effect properties - eg: {frames: 30}
	// @param function     An optional callback function
	//
	this.grow = function()
	{
		// Cancel any stop request if one is pending
		this.cancelStopAnimation();

		var obj       = this;
		var opt       = arguments[0] || {};
		var frames    = opt.frames || 30;
		var frame     = 0;
		var current   = this.currentValue || 0;
		var origValue = Number(obj.currentValue);
		var newValue  = this.value;
		var diff      = newValue - origValue;
		var step      = (diff / frames);
		var callback  = arguments[1] || function () {};



		function iterator ()
		{
			if (obj.stopAnimationRequested) {

				// Reset the flag
				obj.stopAnimationRequested = false;

				return;
			}

			obj.value = origValue + (frame * step);

			DxChart.clear(obj.canvas);
			DxChart.redrawCanvas(obj.canvas);

			if (frame++ < frames) {
				DxChart.Effects.updateCanvas(iterator);
			} else {
				callback(obj);
			}
		}

		iterator();
		
		return this;
	};

