		this.drawAxes();
		this.drawTicks();                
		this.drawLeftBars();
		this.drawRightBars();

		// Redraw the bars so that shadows on not on top
		if (properties.leftVisible) this.drawLeftBars({shadow: false});
		if (properties.rightVisible) this.drawRightBars({shadow: false});


		this.drawAxes();

		this.drawLabels();
