		var textAlignColumn = conf.textAlignColumn;
		
		// ICON
		var iconColumn 		= conf.iconColumn;
		var iconColorColumn = conf.iconColorColumn;
		var iconSizeColumn 	= conf.iconSizeColumn;
		var iconBorderStyleColumn = conf.iconBorderStyleColumn;
		var iconStyleColumn = conf.iconStyleColumn;
		
		var arrTextCol = [];
		if(textColumn) {
			var arrText = textColumn.split(",");
			for(var i=0;i<arrText.length;i++) {
				arrTextCol.push(arrText[i]);
			}
		}
		
		var arrTextColorCol = [];
		if(textColorColumn) {
			var arrTextColor = textColorColumn.split(",");
			for(var i=0;i<arrTextColor.length;i++) {
				arrTextColorCol.push(arrTextColor[i]);
			}
		}
		
		var arrTextAlignCol = [];
