	this.allowAdjusting = function() {return;};








	//
	// This method handles the changing calculation for when the mouse
	// is moved
	// 
	// @param object e The event object
	//
	this.changing_mousemove = function(e)
	{
		var properties = this.properties;	
		//
		// Handle changing for the HProgress
		//
		if (properties.changeableValue && DxChart.Registry.get('changing') && DxChart.Registry.get('changing').uid == this.uid) {

			var mouseXY = DxChart.getMouseXY(e);
			var value   = this.getValue(e);
			
			if (typeof value === 'number') {

				// Fire the onadjust event
				DxChart._fireEvent(this, 'onadjust');

				this.value = Number(value.toFixed(properties.scaleDecimals));
				DxChart.redrawCanvas(this.canvas);
			}
		}
	};








	//
	// Draws labelsSpecific
	//
	this.drawSpecificLabels = function()
	{
		var properties = this.properties;	
		var labels = properties.labelsSpecificClon;

		if (labels) {

			var halign = properties.labelsPosition === 'right' ? 'left' : 'right';
			var step   = this.height / (labels.length - 1);

			this.context.beginPath();

				this.context.fillStyle = properties.textColor;
				if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);

				for (var i=0; i<labels.length; ++i) {

					var textInfo = DxChart.getTextInfo({
						object: this,
						prefix: 'labels'
					});

					DxChart.text({
				
				object: this,

					 font: textInfo.font,
					 size: textInfo.size,
					color: textInfo.color,
					 bold: textInfo.bold,
				   italic: textInfo.italic,

						x:          properties.labelsPosition == 'right' ? this.canvas.width - this.marginRight + 7 : this.marginLeft - 7,
						y:          (this.height + this.marginTop) - (step * i),
						text:       labels[i],
						valign:     'center',
						halign:     halign,
						tag:        'labels.specific',
					  cssClass:     properties.labelsSpecific
									? DxChart.getLabelsCSSClassName({
										object: this,
										  name: 'labelsClass',
										 index: i
									  })
									: ''
					});
				}
			this.context.fill();
		}
	};








	//
	// This function returns the appropriate Y coordinate for the given Y value
	// 
	// @param  int value The Y value you want the coordinate for
	// @returm int       The coordinate
	//
	this.getYCoord = function(value)
	{
		var properties = this.properties;	
		if (value > this.max || value < this.min) {
			return null;
		}

		var barHeight = this.canvas.height - properties.marginTop - properties.marginBottom;
		var coord = ((value - this.min) / (this.max - this.min)) * barHeight;
		coord = this.canvas.height - coord - properties.marginBottom;
		
		return coord;
	};








	//
	// This returns true/false as to whether the cursor is over the chart area.
	// The cursor does not necessarily have to be over the bar itself.
	//
	this.overChartArea = function(e)
	{
		var mouseXY = DxChart.getMouseXY(e);
		var mouseX  = mouseXY[0];
		var mouseY  = mouseXY[1];

		if (   mouseX >= this.marginLeft
			&& mouseX <= (this.canvas.width - this.marginRight)
			&& mouseY >= this.marginTop
			&& mouseY <= (this.canvas.height - this.marginBottom)
			) {
			
			return true;
		}

		return false;
	};








	//
	// 
	//
	this.parseColors = function()
	{
		var properties = this.properties;	
		// Save the original colors so that they can be restored when the canvas is reset
		if (this.original_colors.length === 0) {
			this.original_colors.colors              = DxChart.arrayClone(properties.colors);
			this.original_colors.tickmarksInnerColor = DxChart.arrayClone(properties.tickmarksInnerColor);
			this.original_colors.tickmarksOuterColor = DxChart.arrayClone(properties.tickmarksOuterColor);
			this.original_colors.colorsStrokeInner   = DxChart.arrayClone(properties.colorsStrokeInner);
			this.original_colors.colorsStrokeOuter   = DxChart.arrayClone(properties.colorsStrokeOuter);
			this.original_colors.highlightFill       = DxChart.arrayClone(properties.highlightFill);
			this.original_colors.highlightStroke     = DxChart.arrayClone(properties.highlightStroke);
			this.original_colors.backgroundColor     = DxChart.arrayClone(properties.backgroundColor);
		}

		var colors = properties.colors;

		for (var i=0,len=colors.length; i<len; ++i) {
			colors[i] = this.parseSingleColorForGradient(colors[i]);
		}

		properties.tickmarksInnerColor = this.parseSingleColorForGradient(properties.tickmarksInnerColor);
		properties.tickmarksOuterColor = this.parseSingleColorForGradient(properties.tickmarksOuterColor);
		properties.colorsStrokeInner   = this.parseSingleColorForGradient(properties.colorsStrokeInner);
		properties.colorsStrokeOuter   = this.parseSingleColorForGradient(properties.colorsStrokeOuter);
		properties.highlightFill       = this.parseSingleColorForGradient(properties.highlightFill);
		properties.highlightStroke     = this.parseSingleColorForGradient(properties.highlightStroke);
		properties.backgroundColor     = this.parseSingleColorForGradient(properties.backgroundColor);
	};








	//
	// Use this function to reset the object to the post-constructor state. Eg reset colors if
	// need be etc
	//
	this.reset = function()
	{
	};







	//
	// Draws the bevel effect
	//
	this.drawBevel = function()
	{
		var properties = this.properties;	
		// In case of multiple segments - this adds up all the lengths
		for (var i=0,height=0; i<this.coords.length; ++i) {
			height += this.coords[i][3];
		}

		this.context.save();
			this.context.beginPath();
			this.context.rect(
				this.coords[0][0],
				this.coords[this.coords.length - 1][1] - 1,
				this.coords[0][2],
				height
			);
			this.context.clip();

			this.context.save();
				// Draw a path to clip to
				this.context.beginPath();
					this.drawCurvedBar({
						x:      this.coords[0][0],
						y:      this.coords[this.coords.length - 1][1] - 1,
						width:  this.coords[0][2],
						height: height
					});
					this.context.clip();
				
				// Now draw the rect with a shadow
				this.context.beginPath();
					
					this.context.shadowColor = 'black';
					this.context.shadowOffsetX = 0;
					this.context.shadowOffsetY = 0;
					this.context.shadowBlur    = 15;
						
					if(isNexacroRuntime) this.context.setElementShadowColor(this.context.shadowColor);
					if(isNexacroRuntime) this.context.setElementShadowBlur(this.context.shadowBlur);
					if(isNexacroRuntime) this.context.setElementShadowOffsetX(this.context.shadowOffsetX);
					if(isNexacroRuntime) this.context.setElementShadowOffsetY(this.context.shadowOffsetY);						
					
					this.context.lineWidth = 2;
					if(isNexacroRuntime) this.context.setElementLineWidth(this.context.lineWidth);

					this.drawCurvedBar({
						x: this.coords[0][0] - 1,
						y: this.coords[this.coords.length - 1][1] - 1,
						width:  this.coords[0][2] + 2,
						height: height + 2 + 100
					});
				
				this.context.stroke();

			this.context.restore();
		this.context.restore();
	};








	//
	// This function handles highlighting an entire data-series for the interactive
	// key
	// 
	// @param int index The index of the data series to be highlighted
	//
	this.interactiveKeyHighlight = function(index)
	{
		var properties = this.properties;	
		var coords = this.coords[index];

		this.context.beginPath();

			this.context.strokeStyle = properties.keyInteractiveHighlightChartStroke;
			if(isNexacroRuntime) this.context.setElementStrokeStyle(this.context.strokeStyle);
			this.context.lineWidth    = 2;
			if(isNexacroRuntime) this.context.setElementLineWidth(this.context.lineWidth);
			this.context.fillStyle   = properties.keyInteractiveHighlightChartFill;
			if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);

			this.context.rect(coords[0] - 0.5, coords[1] - 0.5, coords[2] + 1, coords[3] + 1);
		this.context.fill();
		this.context.stroke();
		
		// Reset the lineWidth
		this.context.lineWidth    = 1;
		if(isNexacroRuntime) this.context.setElementLineWidth(this.context.lineWidth);
	};







	//
	// Draws a bar with a curved end
	// 
	// DOESN'T DRAW A CURVED BAR ANY MORE - JUST A REGULAR SQUARE ENDED BAR
	// 
	// @param object opt The coords and colours
	//
	this.drawCurvedBar = function(opt)
	{
		
		this.path(
			'b r % % % % c',
			opt.x,opt.y,opt.width,opt.height
		);

		if (opt.stroke) {
			this.context.strokeStyle = opt.stroke;
			if(isNexacroRuntime) this.context.setElementStrokeStyle(this.context.strokeStyle);
			this.context.stroke();
		}
		
		if (opt.fill) {
			this.context.fillStyle = opt.fill;
			if(isNexacroRuntime) this.context.setElementFillStyle(this.context.fillStyle);
			
			this.context.fill();
		}
	};








