	//
	// Waterfall Grow
	// 
	// @param object Options. You can pass frames here - which should be a number
	// @param function An optional function which is called when the animation is finished
	//
	this.grow = function()
	{
		// Cancel any stop request if one is pending
		this.cancelStopAnimation();

		var opt      = arguments[0] || {},
			callback = arguments[1] || function () {},
			frames   = opt.frames || 30,
			numFrame = 0,
			obj      = this,
			data     = DxChart.arrayClone(this.orgData);
		
		// Reset The data to zeros
		for (var i=0,len=this.data.length; i<len; ++i) {
			this.data[i] /= frames;
		}
		
		//
		// Fix the scale
		//
		if (this.get('yaxisScaleMax') == null) {
			var max   = this.getMax(data);
			var scale2 = DxChart.getScale({object: this, options: {'scale.max': max}});
			this.set('yaxisScaleMax', scale2.max);
		}

		function iterator ()
		{
			if (obj.stopAnimationRequested) {

				// Reset the flag
				obj.stopAnimationRequested = false;

				return;
			}



			for (var i=0; i<obj.data.length; ++i) {
				
				// This produces a very slight easing effect
				obj.data[i] = data[i] * DxChart.Effects.getEasingMultiplier(frames, numFrame);
			}
			
			DxChart.clear(obj.canvas);
			DxChart.redrawCanvas(obj.canvas);

			if (++numFrame <= frames) {
				DxChart.Effects.updateCanvas(iterator,obj.canvas);
			} else {
				callback(obj);
			}
		}
		
		iterator();
		
		return this;
	};








