			if(isNexacroRuntime) this.context.setElementShadowColor(this.context.shadowColor);
			if(isNexacroRuntime) this.context.setElementShadowBlur(this.context.shadowBlur);
			if(isNexacroRuntime) this.context.setElementShadowOffsetX(this.context.shadowOffsetX);
			if(isNexacroRuntime) this.context.setElementShadowOffsetY(this.context.shadowOffsetY);				
